import type { PracticeResult, DiffFile } from "../lib/types";
import { findFiles, readFileLines } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints = [];
  const swiftFiles = await findFiles(repoPath, "swift");

  for (const filePath of swiftFiles) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    const allText = [...lines.values()].join("\n");

    // Only View files
    if (!/:\s*View\s*\{/.test(allText)) continue;
    if (/import\s+XCTest|import\s+Testing/.test(allText)) continue;
    // Skip @main app entry
    if (/@main/.test(allText)) continue;

    // Count #Preview blocks
    let previewCount = 0;
    const previewLines: number[] = [];
    for (const [lineNum, line] of lines) {
      if (/#Preview/.test(line)) {
        previewCount++;
        previewLines.push(lineNum);
      }
    }

    // Measure view complexity (conditionals, state properties)
    let hasConditional = false;
    let stateCount = 0;
    let hasSwitchInBody = false;
    for (const [lineNum, line] of lines) {
      if (/@State\s/.test(line)) stateCount++;
      if (/\bif\s+.*\{|else\s*\{|switch\s+/.test(line)) {
        // Check if inside body
        hasConditional = true;
      }
      if (/\bswitch\s+/.test(line)) hasSwitchInBody = true;
    }

    const isComplex = stateCount > 2 || hasConditional || hasSwitchInBody;
    const inDiff = [...diffFiles.keys()].some(k => relPath.endsWith(k) || k.endsWith(relPath));

    if (isComplex && previewCount === 0) {
      hints.push({
        file: relPath, line: 1, pattern: "complex-view-no-preview",
        context: `Complex view (${stateCount} @State, conditionals: ${hasConditional}) with no #Preview`,
        inDiff,
        flags: { stateCount, hasConditional, hasSwitchInBody, previewCount: 0 },
      });
    } else if (isComplex && previewCount === 1 && (hasSwitchInBody || stateCount > 3)) {
      hints.push({
        file: relPath, line: previewLines[0], pattern: "complex-view-single-preview",
        context: `Complex view with only 1 #Preview — consider covering multiple states`,
        inDiff,
        flags: { stateCount, hasConditional, hasSwitchInBody, previewCount },
      });
    }
  }

  const metrics = {
    totalHints: hints.length,
    noPreview: hints.filter(h => h.pattern === "complex-view-no-preview").length,
    singlePreview: hints.filter(h => h.pattern === "complex-view-single-preview").length,
    inDiffHints: hints.filter(h => h.inDiff).length,
  };

  const directions: string[] = [];
  const noPreviewDiff = hints.filter(h => h.pattern === "complex-view-no-preview" && h.inDiff);
  if (noPreviewDiff.length > 0) {
    directions.push(`${noPreviewDiff.length} complex view(s) on changed lines with NO #Preview — should have preview blocks`);
  }
  const singleDiff = hints.filter(h => h.pattern === "complex-view-single-preview" && h.inDiff);
  if (singleDiff.length > 0) {
    directions.push(`${singleDiff.length} complex view(s) with only 1 preview — multiple states should be previewed`);
  }
  if (directions.length === 0 && hints.length > 0) {
    directions.push("Preview coverage looks adequate for changed views");
  }
  if (hints.length === 0) {
    directions.push("No preview issues detected");
  }

  return { practice: "preview-quality", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { findFiles, readFileLines } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

const VALUE_TYPE_NAMES = new Set([
  "Bool", "Int", "Double", "Float", "String", "Date", "UUID", "URL",
  "CGFloat", "CGPoint", "CGSize", "CGRect", "Color", "TimeInterval",
  "Data", "Decimal", "IndexSet", "AttributedString",
]);

function looksLikeReferenceType(typeName: string): boolean {
  if (!typeName || !/^[A-Z]/.test(typeName)) return false;
  const inner = typeName.replace(/[\[\]?]*/g, "");
  if (VALUE_TYPE_NAMES.has(inner)) return false;
  return true;
}

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints: Array<{ file: string; line: number; pattern: string; context: string; inDiff: boolean; flags: Record<string, any> }> = [];
  const swiftFiles = await findFiles(repoPath, "swift");

  for (const filePath of swiftFiles) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    const allText = [...lines.values()].join("\n");

    if (/import\s+XCTest|import\s+Testing/.test(allText)) continue;

    // Track deprecated patterns in all files
    for (const [lineNum, line] of lines) {
      if (line.trimStart().startsWith("//")) continue;

      if (/:\s*.*\bObservableObject\b/.test(line)) {
        hints.push({ file: relPath, line: lineNum, pattern: "deprecated-observable-object", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { severity: "minor" } });
      }
      if (/@Published\s/.test(line)) {
        hints.push({ file: relPath, line: lineNum, pattern: "deprecated-published", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { severity: "minor" } });
      }
    }

    // View-specific checks
    if (!/:\s*(?:\w+\s*,\s*)*View\s*[,{]/.test(allText)) continue;

    // Build preview line ranges to skip
    const previewRanges: Array<[number, number]> = [];
    let pvStart = -1, pvDepth = 0;
    for (const [lineNum, line] of lines) {
      if (/#Preview\b/.test(line)) { pvStart = lineNum; pvDepth = 0; }
      if (pvStart >= 0) {
        pvDepth += (line.match(/{/g) ?? []).length - (line.match(/}/g) ?? []).length;
        if (pvDepth <= 0 && lineNum > pvStart) { previewRanges.push([pvStart, lineNum]); pvStart = -1; }
      }
    }
    const isInPreview = (ln: number) => previewRanges.some(([s, e]) => ln >= s && ln <= e);

    let bindingCount = 0;

    for (const [lineNum, line] of lines) {
      if (isInPreview(lineNum)) continue;
      if (line.trimStart().startsWith("//")) continue;

      // CRITICAL: @ObservedObject creating instance
      if (/@ObservedObject\s/.test(line)) {
        const m = line.match(/var\s+(\w+)/);
        if (m) {
          if (/=\s*\w+\(/.test(line)) {
            hints.push({ file: relPath, line: lineNum, pattern: "observed-object-creates-instance", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { name: m[1], severity: "critical" } });
          } else {
            hints.push({ file: relPath, line: lineNum, pattern: "deprecated-observed-object", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { name: m[1], severity: "minor" } });
          }
        }
      }

      // Deprecated @StateObject
      if (/@StateObject\s/.test(line) && !/@Previewable/.test(line)) {
        const m = line.match(/var\s+(\w+)/);
        hints.push({ file: relPath, line: lineNum, pattern: "deprecated-state-object", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { name: m?.[1] ?? "unknown", severity: "minor" } });
      }

      // Deprecated @EnvironmentObject
      if (/@EnvironmentObject\s/.test(line)) {
        const m = line.match(/var\s+(\w+)/);
        hints.push({ file: relPath, line: lineNum, pattern: "deprecated-environment-object", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { name: m?.[1] ?? "unknown", severity: "minor" } });
      }

      // didSet on @State
      if (/@State\s/.test(line)) {
        const nextLines = [];
        for (let i = lineNum; i <= lineNum + 3 && lines.has(i); i++) nextLines.push(lines.get(i) ?? "");
        if (/\b(didSet|willSet)\s*\{/.test(nextLines.join(" "))) {
          hints.push({ file: relPath, line: lineNum, pattern: "didset-on-state", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { severity: "major" } });
        }
      }

      // @State analysis
      if (/@State\s/.test(line) && !/@StateObject/.test(line)) {
        const m = line.match(/(private\s+)?var\s+(\w+)(?:\s*:\s*([A-Z]\w+))?/);
        if (m) {
          const isPrivate = !!m[1];
          const hasDefault = /=\s/.test(line);
          const typeName = m[3];

          if (!isPrivate && !/#Preview|Previewable/.test(line)) {
            hints.push({ file: relPath, line: lineNum, pattern: "state-not-private", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { name: m[2] } });
          }
          if (!isPrivate && !hasDefault) {
            hints.push({ file: relPath, line: lineNum, pattern: "state-without-default", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { name: m[2], severity: "major" } });
          }
          if (!hasDefault && typeName && looksLikeReferenceType(typeName)) {
            hints.push({ file: relPath, line: lineNum, pattern: "state-received-reference-type", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { name: m[2], type: typeName, severity: "major" } });
          }
        }
      }

      if (/@Binding\s/.test(line)) bindingCount++;
    }

    // ViewModel creating own ModelContainer
    if (/ModelContainer\s*\(/.test(allText)) {
      let inInit = false, initDepth = 0;
      for (const [lineNum, line] of lines) {
        if (/\binit\s*\(/.test(line)) { inInit = true; initDepth = 0; }
        if (inInit) {
          initDepth += (line.match(/{/g) ?? []).length - (line.match(/}/g) ?? []).length;
          if (/ModelContainer\s*\(/.test(line) && !line.trimStart().startsWith("//")) {
            hints.push({ file: relPath, line: lineNum, pattern: "viewmodel-creates-model-container", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { severity: "major" } });
          }
          if (initDepth <= 0 && lineNum > 1) inInit = false;
        }
      }
    }

    if (bindingCount >= 5) {
      hints.push({ file: relPath, line: 1, pattern: "excessive-binding-drilling", context: `${bindingCount} @Binding properties`, inDiff: [...diffFiles.keys()].some(k => relPath.endsWith(k) || k.endsWith(relPath)), flags: { bindingCount, severity: "minor" } });
    }
  }

  const metrics: Record<string, number> = {
    totalHints: hints.length,
    observedObjectCreates: hints.filter(h => h.pattern === "observed-object-creates-instance").length,
    deprecatedStateObject: hints.filter(h => h.pattern === "deprecated-state-object").length,
    deprecatedObservedObject: hints.filter(h => h.pattern === "deprecated-observed-object").length,
    deprecatedEnvironmentObject: hints.filter(h => h.pattern === "deprecated-environment-object").length,
    deprecatedObservableObject: hints.filter(h => h.pattern === "deprecated-observable-object").length,
    deprecatedPublished: hints.filter(h => h.pattern === "deprecated-published").length,
    didSetOnState: hints.filter(h => h.pattern === "didset-on-state").length,
    stateNotPrivate: hints.filter(h => h.pattern === "state-not-private").length,
    stateWithoutDefault: hints.filter(h => h.pattern === "state-without-default").length,
    stateReceivedRefType: hints.filter(h => h.pattern === "state-received-reference-type").length,
    viewmodelCreatesContainer: hints.filter(h => h.pattern === "viewmodel-creates-model-container").length,
    excessiveBindings: hints.filter(h => h.pattern === "excessive-binding-drilling").length,
    inDiffHints: hints.filter(h => h.inDiff).length,
  };

  const directions: string[] = [];
  const critical = hints.filter(h => h.flags.severity === "critical" && h.inDiff);
  if (critical.length > 0) directions.push(`CRITICAL: ${critical.length} @ObservedObject creating instance(s) — object destroyed on re-render`);

  const didSet = hints.filter(h => h.pattern === "didset-on-state" && h.inDiff);
  if (didSet.length > 0) directions.push(`didSet on @State never fires — use .onChange(of:) instead`);

  const container = hints.filter(h => h.pattern === "viewmodel-creates-model-container" && h.inDiff);
  if (container.length > 0) directions.push(`ViewModel creates own ModelContainer — belongs at App level`);

  const receivedRef = hints.filter(h => h.pattern === "state-received-reference-type" && h.inDiff);
  if (receivedRef.length > 0) directions.push(`@State on reference type without default — freezes after first render`);

  const deprecated = hints.filter(h => h.pattern.startsWith("deprecated-") && h.inDiff);
  if (deprecated.length > 0) {
    const patterns = [...new Set(deprecated.map(h => h.pattern.replace("deprecated-", "")))].join(", ");
    directions.push(`${deprecated.length} deprecated pattern(s): ${patterns} — migrate to @Observable`);
  }

  const stateIssues = hints.filter(h => h.pattern === "state-without-default" && h.inDiff);
  if (stateIssues.length > 0) directions.push(`${stateIssues.length} @State without default on changed lines`);

  const bindings = hints.filter(h => h.pattern === "excessive-binding-drilling" && h.inDiff);
  if (bindings.length > 0) directions.push(`View(s) with 5+ @Binding — pass @Observable with @Bindable`);

  if (directions.length === 0) {
    if (hints.length > 0) directions.push("No state ownership issues on changed lines");
    else directions.push("No state ownership patterns detected");
  }

  return { practice: "state-ownership", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { findFiles, readFileLines } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

const STRUCTURAL_CONTAINERS = new Set([
  "VStack", "HStack", "ZStack", "LazyVStack", "LazyHStack", "LazyVGrid", "LazyHGrid",
  "List", "Form", "ScrollView", "Group", "NavigationStack", "NavigationSplitView", "TabView", "Section",
]);
const CONTAINER_RE = new RegExp(`\\b(${[...STRUCTURAL_CONTAINERS].join("|")})\\s*(?:\\(.*?\\))?\\s*\\{`);

interface ViewInfo {
  file: string; structName: string; bodyStart: number; bodyEnd: number;
  bodyLines: number; stateCount: number; stateProps: string[];
  maxNestingDepth: number; topLevelContainers: number;
  hasDuplicatedFetch: boolean; inDiff: boolean;
}

function detectDuplicatedFetch(lines: Map<number, string>, bodyStart: number, bodyEnd: number): boolean {
  const taskBodies: string[] = [];
  const refreshBodies: string[] = [];
  let modifier: "task" | "refreshable" | null = null;
  let depth = 0; let body = ""; let tracking = false;

  for (let i = bodyStart; i <= bodyEnd; i++) {
    const line = lines.get(i) ?? "";
    const t = line.trim();
    if (!tracking) {
      if (/\.task\s*(\(.*?\))?\s*\{/.test(t)) { modifier = "task"; tracking = true; depth = 0; body = ""; }
      else if (/\.refreshable\s*\{/.test(t)) { modifier = "refreshable"; tracking = true; depth = 0; body = ""; }
    }
    if (tracking) {
      for (const ch of line) { if (ch === "{") depth++; if (ch === "}") depth--; }
      body += t + "\n";
      if (depth <= 0 && body.length > 0) {
        const norm = body.replace(/\.(task|refreshable)\s*(\(.*?\))?\s*\{/, "").replace(/\}[\s]*$/, "").replace(/\s+/g, " ").trim();
        if (modifier === "task") taskBodies.push(norm); else refreshBodies.push(norm);
        tracking = false; modifier = null; body = "";
      }
    }
  }
  for (const tb of taskBodies) {
    if (tb.length < 10) continue;
    for (const rb of refreshBodies) {
      if (rb.length < 10) continue;
      if (tb === rb || tb.includes(rb) || rb.includes(tb)) return true;
      const wordsA = new Set(tb.split(/\W+/).filter(Boolean));
      const wordsB = new Set(rb.split(/\W+/).filter(Boolean));
      let inter = 0; for (const w of wordsA) if (wordsB.has(w)) inter++;
      const union = new Set([...wordsA, ...wordsB]).size;
      if (union > 0 && inter / union > 0.8) return true;
    }
  }
  return false;
}

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints: Array<{ file: string; line: number; pattern: string; context: string; inDiff: boolean; flags: Record<string, any> }> = [];
  const swiftFiles = await findFiles(repoPath, "swift");
  const views: ViewInfo[] = [];

  for (const filePath of swiftFiles) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    const allText = [...lines.values()].join("\n");
    if (!/:\s*View\s*\{/.test(allText)) continue;
    if (/import\s+XCTest|import\s+Testing/.test(allText)) continue;

    for (const [lineNum, line] of lines) {
      const sm = line.match(/struct\s+(\w+)\s*:\s*(?:.*\bView\b)/);
      if (!sm) continue;
      const structName = sm[1];

      // Skip @main app structs
      let isMain = false;
      for (let i = Math.max(1, lineNum - 3); i < lineNum; i++) if (/@main/.test(lines.get(i) ?? "")) isMain = true;
      if (isMain) continue;

      // Find body
      let bodyStart = 0;
      for (let i = lineNum; i <= Math.min(lineNum + 50, lines.size); i++) {
        if (/var\s+body\s*:\s*some\s+View\s*\{/.test(lines.get(i) ?? "")) { bodyStart = i; break; }
      }
      if (!bodyStart) continue;

      // Find body end
      let bodyEnd = 0, d = 0, started = false;
      for (let i = bodyStart; i <= lines.size; i++) {
        for (const ch of (lines.get(i) ?? "")) { if (ch === "{") { d++; started = true; } if (ch === "}") d--; }
        if (started && d <= 0) { bodyEnd = i; break; }
      }
      if (!bodyEnd) bodyEnd = lines.size;
      const bodyLines = bodyEnd - bodyStart - 1;
      if (bodyLines < 10) continue;

      // Count @State between struct and body
      const stateProps: string[] = [];
      for (let i = lineNum; i < bodyStart; i++) {
        const l = lines.get(i) ?? "";
        if (/@State\s/.test(l)) { const pm = l.match(/var\s+(\w+)/); if (pm) stateProps.push(pm[1]); }
      }

      // Nesting depth + top-level containers
      let maxContainerDepth = 0, containerStack = 0, topLevelContainers = 0, relDepth = 0;
      for (let i = bodyStart; i <= bodyEnd; i++) {
        const l = lines.get(i) ?? "";
        const isContainer = CONTAINER_RE.test(l) && !/^\s*\/\//.test(l);
        if (isContainer) {
          if (relDepth === 1) topLevelContainers++;
          containerStack++;
          maxContainerDepth = Math.max(maxContainerDepth, containerStack);
        }
        for (const ch of l) {
          if (ch === "{") relDepth++;
          if (ch === "}") { relDepth--; if (containerStack > 0 && relDepth < containerStack) containerStack = Math.max(0, relDepth); }
        }
      }

      const hasDuplicatedFetch = detectDuplicatedFetch(lines, bodyStart, bodyEnd);
      const fileInDiff = [...diffFiles.keys()].some(k => relPath.endsWith(k) || k.endsWith(relPath));

      const view: ViewInfo = { file: relPath, structName, bodyStart, bodyEnd, bodyLines, stateCount: stateProps.length, stateProps, maxNestingDepth: maxContainerDepth, topLevelContainers, hasDuplicatedFetch, inDiff: fileInDiff };
      views.push(view);

      // Hints
      if (bodyLines > 50) {
        const severity = bodyLines > 120 ? "critical" : bodyLines > 80 ? "major" : "minor";
        hints.push({ file: relPath, line: bodyStart, pattern: "large-body", context: `${structName}.body: ${bodyLines} lines (L${bodyStart}-L${bodyEnd})`, inDiff: fileInDiff, flags: { bodyLines, structName, severity } });
      }
      if (stateProps.length > 5) {
        const severity = stateProps.length > 12 ? "major" : stateProps.length > 8 ? "minor" : "info";
        hints.push({ file: relPath, line: lineNum, pattern: "many-state-props", context: `${structName}: ${stateProps.length} @State [${stateProps.slice(0, 5).join(", ")}]`, inDiff: fileInDiff, flags: { stateCount: stateProps.length, severity } });
      }
      if (maxContainerDepth > 5) {
        hints.push({ file: relPath, line: bodyStart, pattern: "deep-nesting", context: `${structName}.body: ${maxContainerDepth} nesting levels`, inDiff: fileInDiff, flags: { maxDepth: maxContainerDepth } });
      }
      if (topLevelContainers >= 4) {
        hints.push({ file: relPath, line: bodyStart, pattern: "container-sprawl", context: `${structName}.body: ${topLevelContainers} top-level containers`, inDiff: fileInDiff, flags: { topLevelContainers } });
      }
      if (hasDuplicatedFetch) {
        hints.push({ file: relPath, line: bodyStart, pattern: "duplicated-fetch", context: `${structName}: .task and .refreshable duplicate fetch logic`, inDiff: fileInDiff, flags: { structName } });
      }
    }
  }

  const metrics: Record<string, number> = {
    totalViews: views.length,
    viewsOver50: views.filter(v => v.bodyLines > 50).length,
    viewsOver80: views.filter(v => v.bodyLines > 80).length,
    viewsOver120: views.filter(v => v.bodyLines > 120).length,
    stateOver5: views.filter(v => v.stateCount > 5).length,
    stateOver8: views.filter(v => v.stateCount > 8).length,
    deepNesting: views.filter(v => v.maxNestingDepth > 5).length,
    containerSprawl: views.filter(v => v.topLevelContainers >= 4).length,
    duplicatedFetch: views.filter(v => v.hasDuplicatedFetch).length,
    totalHints: hints.length,
    inDiffHints: hints.filter(h => h.inDiff).length,
  };

  const directions: string[] = [];
  for (const v of views.filter(v => v.bodyLines > 120 && v.inDiff).slice(0, 3))
    directions.push(`CRITICAL: ${v.structName}.body is ${v.bodyLines} lines — must decompose`);
  for (const v of views.filter(v => v.bodyLines > 80 && v.bodyLines <= 120 && v.inDiff).slice(0, 3))
    directions.push(`MAJOR: ${v.structName}.body is ${v.bodyLines} lines — extract subviews`);
  for (const v of views.filter(v => v.bodyLines > 50 && v.bodyLines <= 80 && v.inDiff).slice(0, 2))
    directions.push(`MINOR: ${v.structName}.body is ${v.bodyLines} lines — consider splitting`);
  for (const v of views.filter(v => v.stateCount > 8 && v.inDiff).slice(0, 2))
    directions.push(`${v.stateCount > 12 ? "MAJOR" : "MINOR"}: ${v.structName} has ${v.stateCount} @State — group into @Observable`);
  for (const v of views.filter(v => v.topLevelContainers >= 4 && v.inDiff).slice(0, 2))
    directions.push(`${v.structName}.body has ${v.topLevelContainers} top-level containers — split into subviews`);
  for (const v of views.filter(v => v.hasDuplicatedFetch && v.inDiff).slice(0, 2))
    directions.push(`${v.structName}: .task/.refreshable duplicate fetch — extract shared method`);
  for (const v of views.filter(v => v.maxNestingDepth > 5 && v.inDiff).slice(0, 2))
    directions.push(`${v.structName}.body has ${v.maxNestingDepth} nesting levels — flatten`);

  if (directions.length === 0) {
    const large = views.filter(v => v.bodyLines > 50);
    if (large.length > 0) directions.push(`${large.length} view(s) with body >50 lines — check if in changed files`);
    else directions.push("All views have reasonable body sizes");
  }

  return { practice: "view-decomposition", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { grep, findFiles, readFileLines } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

/** Networking API types that should never appear directly in a View */
const NETWORK_TYPES = ["URLSession", "URLRequest", "HTTPURLResponse", "URLComponents"];

/** Networking method patterns (URLSession.shared.data, etc.) */
const NETWORK_METHOD_PATTERNS = [
  /URLSession\s*\.\s*shared/,
  /\.data\s*\(\s*from:/,
  /\.data\s*\(\s*for:/,
  /\.dataTask\s*\(/,
  /\.download\s*\(\s*from:/,
  /\.upload\s*\(/,
];

/**
 * Check if a file is a View struct by looking for ": View {" conformance.
 * Returns the View struct name(s) found.
 */
function findViewStructs(lines: Map<number, string>): Array<{ name: string; line: number }> {
  const views: Array<{ name: string; line: number }> = [];
  for (const [lineNum, line] of lines) {
    const m = line.match(/struct\s+(\w+)\s*:\s*(?:\w+\s*,\s*)*View\s*[,{]/);
    if (m) {
      views.push({ name: m[1], line: lineNum });
    }
  }
  return views;
}

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints: any[] = [];
  const swiftFiles = await findFiles(repoPath, "swift");

  for (const filePath of swiftFiles) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    const allText = [...lines.values()].join("\n");

    // Only analyze View structs
    const viewStructs = findViewStructs(lines);
    if (viewStructs.length === 0) continue;
    if (/import\s+XCTest|import\s+Testing/.test(allText)) continue;

    const viewNames = viewStructs.map(v => v.name).join(", ");

    // --- CHECK: Networking types in View ---
    for (const pattern of NETWORK_TYPES) {
      for (const [lineNum, line] of lines) {
        if (line.includes(pattern) && !line.trimStart().startsWith("//")) {
          hints.push({
            file: relPath, line: lineNum, pattern: "networking-in-view",
            context: line.trim(),
            inDiff: isInDiff(diffFiles, relPath, lineNum),
            flags: { networkType: pattern, viewName: viewNames },
          });
        }
      }
    }

    // --- CHECK: Networking method calls in View ---
    for (const [lineNum, line] of lines) {
      for (const pattern of NETWORK_METHOD_PATTERNS) {
        if (pattern.test(line) && !line.trimStart().startsWith("//")) {
          // Avoid duplicating if already caught by type check
          if (!hints.some(h => h.file === relPath && h.line === lineNum && h.pattern === "networking-in-view")) {
            hints.push({
              file: relPath, line: lineNum, pattern: "networking-in-view",
              context: line.trim(),
              inDiff: isInDiff(diffFiles, relPath, lineNum),
              flags: { networkType: "method-call", viewName: viewNames },
            });
          }
        }
      }
    }

    // --- CHECK: async/await data fetching directly in View ---
    // Look for Task { ... await ... } patterns where the await calls networking
    for (const [lineNum, line] of lines) {
      // Detect "try await" or "await URLSession" etc. in a view context
      if (/\bawait\b/.test(line) && !line.trimStart().startsWith("//")) {
        // Check if it's a networking call (contains URL-related terms)
        if (/url|URL|fetch|request|api|API|endpoint|data\(from|data\(for/i.test(line)) {
          if (!hints.some(h => h.file === relPath && h.line === lineNum)) {
            hints.push({
              file: relPath, line: lineNum, pattern: "async-fetch-in-view",
              context: line.trim(),
              inDiff: isInDiff(diffFiles, relPath, lineNum),
              flags: { viewName: viewNames },
            });
          }
        }
      }
    }

    // --- CHECK: JSON coding in View ---
    for (const [lineNum, line] of lines) {
      if (/(JSONDecoder|JSONEncoder)\(\)/.test(line) && !line.trimStart().startsWith("//")) {
        hints.push({
          file: relPath, line: lineNum, pattern: "json-coding-in-view",
          context: line.trim(),
          inDiff: isInDiff(diffFiles, relPath, lineNum),
          flags: { viewName: viewNames },
        });
      }
    }

    // --- CHECK: UserDefaults usage in View ---
    for (const [lineNum, line] of lines) {
      if (line.includes("UserDefaults.standard") && !line.trimStart().startsWith("//")) {
        hints.push({
          file: relPath, line: lineNum, pattern: "userdefaults-in-view",
          context: line.trim(),
          inDiff: isInDiff(diffFiles, relPath, lineNum),
          flags: { viewName: viewNames },
        });
      }
    }

    // --- CHECK: Timer usage in View ---
    for (const [lineNum, line] of lines) {
      if ((line.includes("Timer.publish") || line.includes("Timer.scheduledTimer")) && !line.trimStart().startsWith("//")) {
        hints.push({
          file: relPath, line: lineNum, pattern: "timer-in-view",
          context: line.trim(),
          inDiff: isInDiff(diffFiles, relPath, lineNum),
          flags: { viewName: viewNames },
        });
      }
    }

    // --- CHECK: FileManager usage in View ---
    for (const [lineNum, line] of lines) {
      if (line.includes("FileManager.default") && !line.trimStart().startsWith("//")) {
        hints.push({
          file: relPath, line: lineNum, pattern: "filemanager-in-view",
          context: line.trim(),
          inDiff: isInDiff(diffFiles, relPath, lineNum),
          flags: { viewName: viewNames },
        });
      }
    }

    // --- CHECK: Large private methods with domain logic ---
    let currentFunc: { name: string; start: number; depth: number; lines: number } | null = null;
    let privateFuncCount = 0;
    for (const [lineNum, line] of lines) {
      const funcMatch = line.match(/private\s+func\s+(\w+)/);
      if (funcMatch) {
        currentFunc = { name: funcMatch[1], start: lineNum, depth: 0, lines: 0 };
        privateFuncCount++;
      }
      if (currentFunc) {
        currentFunc.lines++;
        for (const ch of line) {
          if (ch === "{") currentFunc.depth++;
          if (ch === "}") currentFunc.depth--;
        }
        if (currentFunc.depth <= 0 && currentFunc.lines > 1) {
          if (currentFunc.lines > 15) {
            // Check if it's UI logic or domain logic
            const funcBody: string[] = [];
            for (let i = currentFunc.start; i < currentFunc.start + currentFunc.lines; i++) {
              funcBody.push(lines.get(i) ?? "");
            }
            const body = funcBody.join("\n");
            const isUILogic = /NavigationLink|\.sheet|\.alert|\.toolbar|Text\(|Image\(|VStack|HStack|Button/.test(body);
            if (!isUILogic) {
              hints.push({
                file: relPath, line: currentFunc.start, pattern: "domain-logic-in-view",
                context: `Private func ${currentFunc.name}(): ${currentFunc.lines} lines of non-UI logic in ${viewNames}`,
                inDiff: isInDiff(diffFiles, relPath, currentFunc.start),
                flags: { funcName: currentFunc.name, lineCount: currentFunc.lines, viewName: viewNames },
              });
            }
          }
          currentFunc = null;
        }
      }
    }

    // --- CHECK: Too many private domain functions in a View ---
    if (privateFuncCount >= 3) {
      hints.push({
        file: relPath, line: 1, pattern: "many-private-funcs-in-view",
        context: `${privateFuncCount} private functions in View struct ${viewNames} — logic should be in a ViewModel`,
        inDiff: [...diffFiles.keys()].some(k => relPath.endsWith(k) || k.endsWith(relPath)),
        flags: { count: privateFuncCount, viewName: viewNames },
      });
    }
  }

  const metrics = {
    totalHints: hints.length,
    networkingInView: hints.filter(h => h.pattern === "networking-in-view").length,
    asyncFetchInView: hints.filter(h => h.pattern === "async-fetch-in-view").length,
    jsonCodingInView: hints.filter(h => h.pattern === "json-coding-in-view").length,
    domainLogicInView: hints.filter(h => h.pattern === "domain-logic-in-view").length,
    userDefaultsInView: hints.filter(h => h.pattern === "userdefaults-in-view").length,
    timerInView: hints.filter(h => h.pattern === "timer-in-view").length,
    fileManagerInView: hints.filter(h => h.pattern === "filemanager-in-view").length,
    manyPrivateFuncs: hints.filter(h => h.pattern === "many-private-funcs-in-view").length,
    inDiffHints: hints.filter(h => h.inDiff).length,
  };

  const directions: string[] = [];

  // Networking is the highest-signal finding
  const networkDiff = hints.filter(h => (h.pattern === "networking-in-view" || h.pattern === "async-fetch-in-view") && h.inDiff);
  if (networkDiff.length > 0) {
    const files = [...new Set(networkDiff.map(h => h.file))];
    const examples = networkDiff.slice(0, 3).map(h => `${h.file}:${h.line} (${h.context.slice(0, 60)})`);
    directions.push(
      `SIGNAL: Networking code directly in View file(s): ${files.join(", ")} — must extract to a service/ViewModel. Locations: ${examples.join("; ")}`
    );
  }

  // JSON coding in view
  const jsonDiff = hints.filter(h => h.pattern === "json-coding-in-view" && h.inDiff);
  if (jsonDiff.length > 0) {
    directions.push(`SIGNAL: JSON encoding/decoding in View file(s): ${[...new Set(jsonDiff.map(h => h.file))].join(", ")} — extract to service layer`);
  }

  // Domain logic in view
  const domainDiff = hints.filter(h => h.pattern === "domain-logic-in-view" && h.inDiff);
  if (domainDiff.length > 0) {
    directions.push(
      `SIGNAL: Domain logic functions in View: ${domainDiff.map(h => `${h.flags.funcName}() (${h.flags.lineCount} lines) in ${h.file}`).join(", ")}`
    );
  }

  // UserDefaults in view
  const userDefaultsDiff = hints.filter(h => h.pattern === "userdefaults-in-view" && h.inDiff);
  if (userDefaultsDiff.length > 0) {
    directions.push(`SIGNAL: UserDefaults.standard used directly in View: ${[...new Set(userDefaultsDiff.map(h => h.file))].join(", ")} — use @AppStorage or extract to ViewModel`);
  }

  // Timer in view
  const timerDiff = hints.filter(h => h.pattern === "timer-in-view" && h.inDiff);
  if (timerDiff.length > 0) {
    directions.push(`SIGNAL: Timer usage in View: ${[...new Set(timerDiff.map(h => h.file))].join(", ")} — move timer logic to ViewModel`);
  }

  // FileManager in view
  const fileManagerDiff = hints.filter(h => h.pattern === "filemanager-in-view" && h.inDiff);
  if (fileManagerDiff.length > 0) {
    directions.push(`SIGNAL: FileManager.default in View: ${[...new Set(fileManagerDiff.map(h => h.file))].join(", ")} — extract to service layer`);
  }

  // Many private funcs
  const manyFuncsDiff = hints.filter(h => h.pattern === "many-private-funcs-in-view" && h.inDiff);
  if (manyFuncsDiff.length > 0) {
    directions.push(`SIGNAL: ${manyFuncsDiff.map(h => `${h.flags.viewName} has ${h.flags.count} private functions`).join("; ")} — domain logic should live in ViewModel`);
  }

  // Non-diff hints summary
  if (directions.length === 0 && hints.length > 0) {
    const inDiffCount = hints.filter(h => h.inDiff).length;
    if (inDiffCount > 0) {
      directions.push(`${inDiffCount} separation concern(s) on changed lines — investigate`);
    } else {
      directions.push(`${hints.length} separation concern(s) in repo but not on changed lines — likely pre-existing`);
    }
  }

  if (hints.length === 0) {
    directions.push("Views properly delegate to services/ViewModels — no logic separation issues found");
  }

  return { practice: "view-logic-separation", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { grep, matchesToHints, readFileLines, findFiles } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints = [];

  // Pattern 1: Debug print() statements (not in catch blocks)
  const prints = await grep("print(", repoPath, { fixedString: true, glob: "*.swift" });
  for (const m of prints) {
    if (m.content.trimStart().startsWith("//")) continue;
    if (/#if DEBUG/.test(m.content)) continue;
    // Skip import statements (e.g. "import os" matches "print(" in "import os.print()" — avoid false positives)
    if (/^import\s/.test(m.content.trimStart())) continue;

    // Check if in catch block (skip — that's silent-failure territory)
    const filePath = `${repoPath}/${m.file}`;
    const lines = await readFileLines(filePath);
    let inCatch = false;
    for (let i = m.line; i >= Math.max(1, m.line - 5); i--) {
      const l = lines.get(i) ?? "";
      if (/}\s*catch|catch\s*\{|catch\s+let/.test(l)) { inCatch = true; break; }
    }
    if (inCatch) continue;

    // Check if it's a print-only button (strongest signal)
    let isPrintOnlyButton = false;
    for (let i = m.line; i >= Math.max(1, m.line - 3); i--) {
      const l = lines.get(i) ?? "";
      if (/Button.*\{/.test(l)) {
        // Check if print is the only action
        let buttonBody = "";
        for (let j = i; j <= Math.min(lines.size, m.line + 2); j++) {
          buttonBody += (lines.get(j) ?? "") + "\n";
        }
        // If the button body only has print() and braces
        const nonPrintLines = buttonBody.split("\n").filter(l => l.trim() && !/Button|print\(|\{|\}/.test(l.trim()));
        if (nonPrintLines.length === 0) isPrintOnlyButton = true;
        break;
      }
    }

    const inDiff = isInDiff(diffFiles, m.file, m.line);
    hints.push({
      file: m.file, line: m.line,
      pattern: isPrintOnlyButton ? "print-only-button" : "debug-print",
      context: m.content,
      inDiff,
      flags: { isPrintOnlyButton },
    });
  }

  // Pattern 2: Xcode placeholder tokens
  const xcodeTokens = await grep("@START_MENU_TOKEN@", repoPath, { fixedString: true, glob: "*.swift" });
  hints.push(...matchesToHints(xcodeTokens, "xcode-placeholder", diffFiles));

  // Pattern 3: Commented-out code blocks (2+ consecutive // lines that look like code)
  const swiftFiles = await findFiles(repoPath, "swift");
  for (const filePath of swiftFiles.slice(0, 50)) { // limit for performance
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    let consecutiveCommentedCode = 0;
    let blockStart = 0;

    for (const [lineNum, line] of lines) {
      const trimmed = line.trim();
      // Is this a commented-out code line? (starts with // and contains code patterns)
      const isCommentedCode = /^\/\/\s*(?:let |var |func |if |for |return |guard |switch |case |struct |class |import |@)/.test(trimmed);

      if (isCommentedCode) {
        if (consecutiveCommentedCode === 0) blockStart = lineNum;
        consecutiveCommentedCode++;
      } else {
        if (consecutiveCommentedCode >= 2) {
          const inDiff = isInDiff(diffFiles, relPath, blockStart);
          hints.push({
            file: relPath, line: blockStart, pattern: "commented-out-code",
            context: `${consecutiveCommentedCode} lines of commented-out code starting at L${blockStart}`,
            inDiff,
            flags: { lineCount: consecutiveCommentedCode },
          });
        }
        consecutiveCommentedCode = 0;
      }
    }
    // Handle block at end of file
    if (consecutiveCommentedCode >= 2) {
      hints.push({
        file: relPath, line: blockStart, pattern: "commented-out-code",
        context: `${consecutiveCommentedCode} lines of commented-out code`,
        inDiff: isInDiff(diffFiles, relPath, blockStart),
        flags: { lineCount: consecutiveCommentedCode },
      });
    }
  }

  // Pattern 4: Stale Xcode file headers (filename doesn't match)
  for (const filePath of swiftFiles.slice(0, 50)) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    const actualName = relPath.split("/").pop() ?? "";
    const firstLine = lines.get(1) ?? "";
    const headerMatch = firstLine.match(/^\/\/\s+(\S+\.swift)/);
    if (headerMatch && headerMatch[1] !== actualName) {
      hints.push({
        file: relPath, line: 1, pattern: "stale-file-header",
        context: `Header says "${headerMatch[1]}" but file is "${actualName}"`,
        inDiff: isInDiff(diffFiles, relPath, 1),
        flags: { headerName: headerMatch[1], actualName },
      });
    }
  }

  // Pattern 5: debugPrint() statements (same logic as print but distinct pattern)
  const debugPrintCalls = await grep("debugPrint(", repoPath, { fixedString: true, glob: "*.swift" });
  for (const m of debugPrintCalls) {
    if (m.content.trimStart().startsWith("//")) continue;
    if (/#if DEBUG/.test(m.content)) continue;
    hints.push({
      file: m.file, line: m.line, pattern: "debug-print-call",
      context: m.content,
      inDiff: isInDiff(diffFiles, m.file, m.line),
      flags: {},
    });
  }

  // Pattern 6: dump() statements
  const dumpCalls = await grep("dump(", repoPath, { fixedString: true, glob: "*.swift" });
  for (const m of dumpCalls) {
    if (m.content.trimStart().startsWith("//")) continue;
    if (/#if DEBUG/.test(m.content)) continue;
    hints.push({
      file: m.file, line: m.line, pattern: "dump-call",
      context: m.content,
      inDiff: isInDiff(diffFiles, m.file, m.line),
      flags: {},
    });
  }

  // Pattern 7: NSLog() statements
  const nslogCalls = await grep("NSLog(", repoPath, { fixedString: true, glob: "*.swift" });
  for (const m of nslogCalls) {
    if (m.content.trimStart().startsWith("//")) continue;
    hints.push({
      file: m.file, line: m.line, pattern: "nslog-call",
      context: m.content,
      inDiff: isInDiff(diffFiles, m.file, m.line),
      flags: {},
    });
  }

  // Pattern 8: TODO/FIXME comments in code (on changed lines)
  const todoComments = await grep("TODO|FIXME", repoPath, { glob: "*.swift" });
  for (const m of todoComments) {
    // Only flag actual comment lines containing TODO/FIXME
    if (!m.content.includes("TODO") && !m.content.includes("FIXME")) continue;
    hints.push({
      file: m.file, line: m.line, pattern: "todo-fixme-comment",
      context: m.content,
      inDiff: isInDiff(diffFiles, m.file, m.line),
      flags: {},
    });
  }

  const metrics = {
    totalHints: hints.length,
    debugPrints: hints.filter(h => h.pattern === "debug-print").length,
    printOnlyButtons: hints.filter(h => h.pattern === "print-only-button").length,
    commentedCode: hints.filter(h => h.pattern === "commented-out-code").length,
    xcodeTokens: hints.filter(h => h.pattern === "xcode-placeholder").length,
    staleHeaders: hints.filter(h => h.pattern === "stale-file-header").length,
    debugPrintCalls: hints.filter(h => h.pattern === "debug-print-call").length,
    dumpCalls: hints.filter(h => h.pattern === "dump-call").length,
    nslogCalls: hints.filter(h => h.pattern === "nslog-call").length,
    todoFixme: hints.filter(h => h.pattern === "todo-fixme-comment").length,
    inDiffHints: hints.filter(h => h.inDiff).length,
  };

  const directions: string[] = [];
  const printButtons = hints.filter(h => h.pattern === "print-only-button" && h.inDiff);
  if (printButtons.length > 0) {
    directions.push(`${printButtons.length} print-only button(s) on changed lines — non-functional UI elements`);
  }
  const debugPrints = hints.filter(h => h.pattern === "debug-print" && h.inDiff);
  if (debugPrints.length > 0) {
    directions.push(`${debugPrints.length} debug print() statement(s) on changed lines — consider removing or using Logger`);
  }
  const commented = hints.filter(h => h.pattern === "commented-out-code" && h.inDiff);
  if (commented.length > 0) {
    directions.push(`${commented.length} commented-out code block(s) on changed lines — git history preserves old code`);
  }
  const debugPrintCallsDiff = hints.filter(h => h.pattern === "debug-print-call" && h.inDiff);
  if (debugPrintCallsDiff.length > 0) {
    directions.push(`${debugPrintCallsDiff.length} debugPrint() call(s) on changed lines — remove or replace with Logger`);
  }
  const dumpDiff = hints.filter(h => h.pattern === "dump-call" && h.inDiff);
  if (dumpDiff.length > 0) {
    directions.push(`${dumpDiff.length} dump() call(s) on changed lines — remove debug output`);
  }
  const nslogDiff = hints.filter(h => h.pattern === "nslog-call" && h.inDiff);
  if (nslogDiff.length > 0) {
    directions.push(`${nslogDiff.length} NSLog() call(s) on changed lines — use os.Logger instead`);
  }
  const todoDiff = hints.filter(h => h.pattern === "todo-fixme-comment" && h.inDiff);
  if (todoDiff.length > 0) {
    directions.push(`${todoDiff.length} TODO/FIXME comment(s) on changed lines — resolve or track in issues`);
  }
  if (directions.length === 0 && hints.length > 0) {
    directions.push(`${hints.length} hygiene issue(s) found in repo — check if any are on changed lines`);
  }
  if (hints.length === 0) {
    directions.push("Code is clean — no debug prints, commented code, or Xcode artifacts");
  }

  return { practice: "code-hygiene", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { grep, findFiles, readFileLines } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

const ALLOWED_SINGLE = new Set(["i", "j", "k", "x", "y", "z", "_"]);
const ALLOWED_SHORT = new Set([
  "id", "url", "key", "val", "err", "req", "res", "row", "col", "idx",
  "num", "max", "min", "str", "msg", "btn", "img", "lhs", "rhs", "api",
  "dto", "vm", "db", "ui",
]);
const BOOL_NAMES = new Set([
  "dirty", "active", "visible", "hidden", "selected", "enabled", "disabled",
  "editing", "loading", "expanded", "collapsed", "open", "closed", "focused",
]);
const KNOWN_ACRONYMS = ["API", "URL", "HTTP", "JSON", "XML", "HTML", "CSS", "SQL", "UI", "ID"];
const ENGLISH_PREFIXES = new Set([
  "get", "set", "new", "old", "the", "for", "all", "any", "has", "can",
  "did", "max", "min", "sub", "pre", "add", "top", "tab", "nav", "bar",
  "row", "col", "end", "use", "run", "log", "map", "key", "tag", "pop",
]);
const GENERIC_NAMES = new Set(["data", "result", "value", "item", "thing", "object", "element", "stuff"]);
const GENERIC_SKIP_RE = /URLSession|Codable|JSONDecoder|JSONEncoder|TaskGroup|ForEach|Result<|\.decode|\.encode/;
const TYPE_SUFFIXES = ["String", "Int", "Array", "Dictionary", "Bool", "Date", "Double", "Float"];

function extractTypeNames(lines: Map<number, string>): Array<{ name: string; line: number; kind: string }> {
  const types: Array<{ name: string; line: number; kind: string }> = [];
  let braceDepth = 0;
  for (const [lineNum, line] of lines) {
    for (const ch of line) {
      if (ch === "{") braceDepth++;
      if (ch === "}") braceDepth--;
    }
    if (braceDepth <= 1) {
      const m = line.match(/^\s*(?:(?:public|private|internal|fileprivate|open|final)\s+)*(?:struct|class|enum|protocol|actor)\s+(\w+)/);
      if (m) types.push({ name: m[1], line: lineNum, kind: line.match(/(struct|class|enum|protocol|actor)/)?.[1] ?? "" });
    }
  }
  return types;
}

function countUsagesInScope(lines: Map<number, string>, varName: string, startLine: number, window: number): number {
  let count = 0;
  for (let i = startLine + 1; i <= startLine + window; i++) {
    const l = lines.get(i);
    if (!l) break;
    const re = new RegExp(`\\b${varName}\\b`);
    if (re.test(l)) count++;
  }
  return count;
}

function checkAcronymCasing(name: string): { acronym: string; suggested: string } | null {
  for (const acr of KNOWN_ACRONYMS) {
    if (name.startsWith(acr) && name.length > acr.length) {
      const rest = name.slice(acr.length);
      if (/^[A-Z]/.test(rest)) {
        const suggested = acr.toLowerCase() + rest;
        return { acronym: acr, suggested };
      }
    }
  }
  return null;
}

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints: Array<{ file: string; line: number; pattern: string; context: string; inDiff: boolean; flags: Record<string, any> }> = [];
  const swiftFiles = await findFiles(repoPath, "swift");

  for (const filePath of swiftFiles) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    const allText = [...lines.values()].join("\n");

    if (/import\s+XCTest|import\s+Testing/.test(allText)) continue;
    if (/Tests?\//.test(relPath)) continue;

    // --- Check 1: snake_case properties ---
    for (const [lineNum, line] of lines) {
      if (line.trimStart().startsWith("//")) continue;
      if (/CodingKey|case\s|@objc|#selector/.test(line)) continue;
      const m = line.match(/\b(?:let|var)\s+(\w+_\w+)/);
      if (m) {
        hints.push({ file: relPath, line: lineNum, pattern: "snake-case-property", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { identifier: m[1] } });
      }
    }

    // --- Check 2: snake_case functions ---
    for (const [lineNum, line] of lines) {
      if (line.trimStart().startsWith("//")) continue;
      const m = line.match(/func\s+(\w+_\w+)/);
      if (m) {
        hints.push({ file: relPath, line: lineNum, pattern: "snake-case-func", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { identifier: m[1] } });
      }
    }

    // --- Check 3: Single-letter vars spanning scope ---
    for (const [lineNum, line] of lines) {
      const m = line.match(/\b(?:let|var)\s+([a-zA-Z])\s*[=:]/);
      if (!m) continue;
      const name = m[1];
      if (ALLOWED_SINGLE.has(name)) continue;
      if (/ForEach|\.map|\.filter|\.reduce|\.forEach|\.flatMap|\.compactMap/.test(line)) continue;
      const usages = countUsagesInScope(lines, name, lineNum, 15);
      if (usages < 1) continue;
      hints.push({ file: relPath, line: lineNum, pattern: "single-letter-var", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { identifier: name, usages } });
    }

    // --- Check 4: Bool without is/has/should prefix ---
    for (const [lineNum, line] of lines) {
      const m = line.match(/\bvar\s+(\w+)\s*[:=]\s*(?:true|false|Bool)/);
      if (!m) continue;
      if (/\b(?:is|has|should|can|did|will|show)\w*/.test(`is${m[1]}`)) continue;
      if (BOOL_NAMES.has(m[1])) {
        const suggestion = `is${m[1].charAt(0).toUpperCase()}${m[1].slice(1)}`;
        hints.push({ file: relPath, line: lineNum, pattern: "bool-without-prefix", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { identifier: m[1], suggestion } });
      }
    }

    // --- Check 5: File-type name mismatch ---
    const fileName = relPath.split("/").pop()?.replace(/\.swift$/, "") ?? "";
    if (fileName) {
      const typeNames = extractTypeNames(lines);
      if (typeNames.length > 0 && typeNames.length < 3) {
        const hasMatch = typeNames.some(t => t.name === fileName || t.name === fileName + "App");
        if (!hasMatch) {
          const fileInDiff = [...diffFiles.keys()].some(k => relPath.endsWith(k) || k.endsWith(relPath));
          if (fileInDiff) {
            const pt = typeNames[0];
            hints.push({ file: relPath, line: pt.line, pattern: "file-type-name-mismatch", context: `File "${fileName}.swift" contains ${pt.kind} "${pt.name}"`, inDiff: true, flags: { fileName, typeName: pt.name, typeKind: pt.kind } });
          }
        }
      }
    }

    // --- Check 6: ALL_CAPS constants ---
    for (const [lineNum, line] of lines) {
      if (line.trimStart().startsWith("//")) continue;
      const m = line.match(/\b(?:let|static\s+let|static\s+var)\s+([A-Z][A-Z_]{2,})\b/);
      if (m) {
        const name = m[1];
        const camel = name.toLowerCase().replace(/_([a-z])/g, (_, c) => c.toUpperCase());
        hints.push({ file: relPath, line: lineNum, pattern: "all-caps-constant", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { identifier: name, suggestion: camel } });
      }
    }

    // --- Check 7: Acronym casing ---
    for (const [lineNum, line] of lines) {
      const m = line.match(/\b(?:let|var)\s+(\w+)/);
      if (!m) continue;
      const acr = checkAcronymCasing(m[1]);
      if (acr) {
        hints.push({ file: relPath, line: lineNum, pattern: "acronym-casing", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { identifier: m[1], acronym: acr.acronym, suggestion: acr.suggested } });
      }
    }

    // --- Check 8: Systematic abbreviation prefix ---
    const propNames: Array<{ name: string; line: number }> = [];
    for (const [lineNum, line] of lines) {
      const m = line.match(/\b(?:let|var|@State.*var|@Binding\s+var)\s+(\w+)/);
      if (m && m[1].length > 3) propNames.push({ name: m[1], line: lineNum });
    }
    const prefixGroups = new Map<string, Array<{ name: string; line: number }>>();
    for (const p of propNames) {
      for (let len = 2; len <= 4 && len < p.name.length; len++) {
        const prefix = p.name.slice(0, len).toLowerCase();
        if (ENGLISH_PREFIXES.has(prefix)) continue;
        if (!prefixGroups.has(prefix)) prefixGroups.set(prefix, []);
        prefixGroups.get(prefix)!.push(p);
      }
    }
    for (const [prefix, members] of prefixGroups) {
      if (members.length >= 3) {
        const uniqueNames = [...new Set(members.map(m => m.name))];
        if (uniqueNames.length >= 3) {
          const fileInDiff = [...diffFiles.keys()].some(k => relPath.endsWith(k) || k.endsWith(relPath));
          hints.push({ file: relPath, line: members[0].line, pattern: "systematic-abbreviation", context: `${uniqueNames.length} properties share prefix "${prefix}": ${uniqueNames.slice(0, 5).join(", ")}`, inDiff: fileInDiff, flags: { prefix, count: uniqueNames.length, names: uniqueNames.slice(0, 5) } });
        }
      }
    }

    // --- Check 9: Magic string sentinels ---
    for (const [lineNum, line] of lines) {
      if (line.trimStart().startsWith("//")) continue;
      if (/\b(print|Text|Label|Logger|log\.|description|title|message|NSLocalizedString)\b/.test(line)) continue;
      const m = line.match(/"([A-Z][A-Z ]{2,})"/);
      if (m && /[=:(]/.test(line)) {
        hints.push({ file: relPath, line: lineNum, pattern: "magic-string-sentinel", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { value: m[1] } });
      }
    }

    // --- Check 10: Generic variable names ---
    for (const [lineNum, line] of lines) {
      if (GENERIC_SKIP_RE.test(line)) continue;
      const m = line.match(/\b(?:let|var)\s+(data|result|value|item|thing|object|element|stuff)\s*[=:]/);
      if (m) {
        hints.push({ file: relPath, line: lineNum, pattern: "generic-name", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { identifier: m[1] } });
      }
    }

    // --- Check 11: Type name in variable ---
    for (const [lineNum, line] of lines) {
      for (const suffix of TYPE_SUFFIXES) {
        const re = new RegExp(`\\b(?:let|var)\\s+(\\w{3,})${suffix}\\s*[=:]`);
        const m = line.match(re);
        if (m && !/^(struct|class|enum|typealias|protocol)\s/.test(line.trim())) {
          hints.push({ file: relPath, line: lineNum, pattern: "type-in-name", context: line.trim(), inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { identifier: m[1] + suffix, suffix } });
        }
      }
    }
  }

  const metrics: Record<string, number> = {
    totalHints: hints.length,
    snakeCaseProps: hints.filter(h => h.pattern === "snake-case-property").length,
    snakeCaseFuncs: hints.filter(h => h.pattern === "snake-case-func").length,
    singleLetterVars: hints.filter(h => h.pattern === "single-letter-var").length,
    boolWithoutPrefix: hints.filter(h => h.pattern === "bool-without-prefix").length,
    fileTypeMismatch: hints.filter(h => h.pattern === "file-type-name-mismatch").length,
    allCapsConstants: hints.filter(h => h.pattern === "all-caps-constant").length,
    acronymCasing: hints.filter(h => h.pattern === "acronym-casing").length,
    systematicAbbreviation: hints.filter(h => h.pattern === "systematic-abbreviation").length,
    magicStringSentinel: hints.filter(h => h.pattern === "magic-string-sentinel").length,
    genericNames: hints.filter(h => h.pattern === "generic-name").length,
    typeInName: hints.filter(h => h.pattern === "type-in-name").length,
    inDiffHints: hints.filter(h => h.inDiff).length,
  };

  const directions: string[] = [];
  const inDiff = hints.filter(h => h.inDiff);

  const highSignal = inDiff.filter(h => ["systematic-abbreviation", "single-letter-var", "acronym-casing", "all-caps-constant", "magic-string-sentinel"].includes(h.pattern));
  for (const h of highSignal.slice(0, 5)) {
    const id = h.flags.identifier ?? h.flags.prefix ?? h.flags.value ?? h.pattern;
    directions.push(`SIGNAL: ${h.pattern} — ${id} in ${h.file}:${h.line}`);
  }

  const lowerSignal = inDiff.filter(h => ["snake-case-property", "snake-case-func", "bool-without-prefix", "generic-name", "type-in-name", "file-type-name-mismatch"].includes(h.pattern));
  if (lowerSignal.length > 0) {
    const examples = lowerSignal.slice(0, 3).map(h => `${h.flags.identifier ?? h.pattern} in ${h.file}:${h.line}`);
    directions.push(`${lowerSignal.length} naming issue(s) on changed lines: ${examples.join(", ")}`);
  }

  if (directions.length === 0 && hints.length > 0) {
    directions.push(`${hints.length} naming issue(s) in repo — check if any on changed lines`);
  }
  if (hints.length === 0) {
    directions.push("Naming looks clean");
  }

  return { practice: "meaningful-naming", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { grep, matchesToHints, readFileLines } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints = [];
  const metrics: Record<string, number> = {};

  // Pattern 1: fatalError
  const fatalErrors = await grep("fatalError(", repoPath, { fixedString: true, glob: "*.swift" });
  const fatalHints = matchesToHints(fatalErrors, "fatalError", diffFiles, m => ({
    inPreview: /#Preview|PreviewProvider/.test(m.content),
    inDebug: /#if DEBUG/.test(m.content),
    isRequiredInit: /required init\??\(coder/.test(m.content),
    isUnknownDefault: /@unknown default/.test(m.content),
  }));
  hints.push(...fatalHints);

  // Pattern 2: try!
  const tryBangs = await grep("try!", repoPath, { glob: "*.swift" });
  // Filter out "try!" in comments
  const tryBangHints = matchesToHints(
    tryBangs.filter(m => !m.content.trimStart().startsWith("//")),
    "try!", diffFiles, m => ({
      inPreview: /#Preview|PreviewProvider/.test(m.content),
      inTest: /XCTest|Testing|@Test/.test(m.content),
    })
  );
  hints.push(...tryBangHints);

  // Pattern 3: Force unwrap (! on values, not != or Type! declarations)
  const forceUnwraps = await grep('[]a-zA-Z0-9_)]!', repoPath, { glob: "*.swift" });
  // Aggressive filter to reduce false positives
  const realForceUnwraps = forceUnwraps.filter(m => {
    const c = m.content;
    if (c.trimStart().startsWith("//")) return false;
    // Skip IUO declarations (: Type!, -> Type!, (Type!) etc.)
    const noIuo = c.replace(/[:(,]\s*[\[(<]*\s*[A-Z]\w*\s*[)>\]]*\s*!/g, "")
                    .replace(/->\s*[\[(<]*\s*[A-Z]\w*\s*[)>\]]*\s*!/g, "");
    if (!noIuo.includes("!") && c.includes("!")) return false;
    if (/!=/.test(c) && !/\w!\./.test(c) && !/\w!\s/.test(c)) return false;
    // Match actual force unwraps: someVar!, .first!, dict[key]!, func()!
    return /\w![\s,\)\.]|!\s*$|\w!$/.test(c) && !/\bfatalError\b/.test(c) && !/\btry!/.test(c) && !/\bas!/.test(c);
  });
  const forceUnwrapHints = matchesToHints(realForceUnwraps, "force-unwrap", diffFiles, m => ({
    inPreview: /#Preview|PreviewProvider/.test(m.content),
  }));
  hints.push(...forceUnwrapHints);

  // Pattern 4: preconditionFailure
  const preconditions = await grep("preconditionFailure(", repoPath, { fixedString: true, glob: "*.swift" });
  hints.push(...matchesToHints(preconditions, "preconditionFailure", diffFiles));

  // Pattern 5: Unguarded array[0] access
  const arrayAccess = await grep('\\[0\\]', repoPath, { glob: "*.swift" });
  const unguardedArray = arrayAccess.filter(m => {
    const c = m.content;
    if (c.trimStart().startsWith("//")) return false;
    // Skip obvious safe patterns
    if (/\.first\b/.test(c)) return false;
    if (/guard|if.*\.isEmpty|\.count\s*>/.test(c)) return false;
    return true;
  });
  hints.push(...matchesToHints(unguardedArray, "unguarded-array-access", diffFiles));

  // Pattern 6: Forced cast (as!)
  const forcedCasts = await grep("as!", repoPath, { glob: "*.swift" });
  const realForcedCasts = forcedCasts.filter(m => {
    const c = m.content;
    if (c.trimStart().startsWith("//")) return false;
    // Must actually contain "as!" cast syntax (word boundary before as!)
    return /\bas!\s/.test(c) || /\bas![A-Z]/.test(c);
  });
  const forcedCastHints = matchesToHints(realForcedCasts, "forced-cast", diffFiles, m => ({
    inPreview: /#Preview|PreviewProvider/.test(m.content),
  }));
  hints.push(...forcedCastHints);

  // Metrics
  const inDiffCount = hints.filter(h => h.inDiff).length;
  const excludedCount = hints.filter(h => h.flags.inPreview || h.flags.inDebug || h.flags.isRequiredInit || h.flags.isUnknownDefault).length;

  metrics.totalMatches = hints.length;
  metrics.inDiffMatches = inDiffCount;
  metrics.excluded = excludedCount;
  metrics.fatalErrors = fatalHints.length;
  metrics.tryBangs = tryBangHints.length;
  metrics.forceUnwraps = forceUnwrapHints.length;
  metrics.forcedCasts = forcedCastHints.length;

  // Directions
  const directions: string[] = [];
  const diffFatalErrors = fatalHints.filter(h => h.inDiff && !h.flags.inPreview && !h.flags.isRequiredInit && !h.flags.isUnknownDefault);
  if (diffFatalErrors.length > 0) {
    directions.push(`${diffFatalErrors.length} fatalError call(s) on changed lines — check if reachable at runtime and suggest guard/throw alternatives`);
  }
  const diffTryBangs = tryBangHints.filter(h => h.inDiff && !h.flags.inPreview && !h.flags.inTest);
  if (diffTryBangs.length > 0) {
    directions.push(`${diffTryBangs.length} try! usage(s) on changed lines — suggest try/catch or try? with fallback`);
  }
  const diffForceUnwraps = forceUnwrapHints.filter(h => h.inDiff && !h.flags.inPreview);
  if (diffForceUnwraps.length > 0) {
    directions.push(`${diffForceUnwraps.length} force unwrap(s) on changed lines — check if guard let or ?? would be safer`);
  }
  const diffForcedCasts = forcedCastHints.filter(h => h.inDiff && !h.flags.inPreview);
  if (diffForcedCasts.length > 0) {
    directions.push(`${diffForcedCasts.length} forced cast(s) (as!) on changed lines — use as? with guard/if-let instead`);
  }
  if (directions.length === 0 && hints.length > 0) {
    directions.push(`${hints.length} crash-risk patterns found in repo, but none on changed lines — likely pre-existing`);
  }
  if (hints.length === 0) {
    directions.push("No crash-risk patterns detected — repo looks clean for this practice");
  }

  return { practice: "fatal-error-crash", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { grep, findFiles, readFileLines } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints: Array<{ file: string; line: number; pattern: string; context: string; inDiff: boolean; flags: Record<string, any> }> = [];
  const metrics: Record<string, number> = {};
  const swiftFiles = await findFiles(repoPath, "swift");

  const filePatternCounts = new Map<string, number>();
  function canAdd(file: string, pattern: string): boolean {
    const key = `${file}::${pattern}`;
    const c = filePatternCounts.get(key) ?? 0;
    if (c >= 2) return false;
    filePatternCounts.set(key, c + 1);
    return true;
  }
  function isTestFile(text: string): boolean { return /import\s+XCTest|import\s+Testing/.test(text); }

  // --- Catch block analysis ---
  const catchMatches = await grep("} catch", repoPath, { glob: "*.swift" });
  for (const match of catchMatches) {
    const filePath = `${repoPath}/${match.file}`;
    const lines = await readFileLines(filePath);
    const allText = [...lines.values()].join("\n");
    if (isTestFile(allText)) continue;

    const catchLine = match.line;
    const blockContent: string[] = [];
    let depth = 0, started = false;
    for (let i = catchLine; i <= catchLine + 30 && i <= lines.size; i++) {
      const line = lines.get(i) ?? "";
      for (const ch of line) { if (ch === "{") { depth++; started = true; } if (ch === "}") depth--; }
      if (i > catchLine) blockContent.push(line.trim());
      if (started && depth <= 0) break;
    }
    const body = blockContent.filter(l => l && l !== "}").join("\n");
    const inDiff = isInDiff(diffFiles, match.file, match.line);

    if (/fatalError\(/.test(body)) continue;
    if (/\bthrow\b/.test(body)) continue;
    const setsError = /errorMessage|errorText|error\s*=|showError|isError|alertMessage/.test(body);
    if (setsError) continue;

    if (!body || body.trim() === "") {
      if (canAdd(match.file, "empty-catch")) hints.push({ file: match.file, line: catchLine, pattern: "empty-catch", context: match.content, inDiff, flags: {} });
    } else if (/^\s*(print\(|debugPrint\()/.test(body) && body.split("\n").filter(l => l.trim() && l.trim() !== "}").length <= 2) {
      if (canAdd(match.file, "catch-only-print")) hints.push({ file: match.file, line: catchLine, pattern: "catch-only-print", context: body.split("\n")[0], inDiff, flags: {} });
    } else if (/(Logger|os_log|log\.)/.test(body) && body.split("\n").filter(l => l.trim() && l.trim() !== "}").length <= 2) {
      if (canAdd(match.file, "catch-only-log")) hints.push({ file: match.file, line: catchLine, pattern: "catch-only-log", context: body.split("\n")[0], inDiff, flags: {} });
    } else if (/^\s*return\s+(nil|\.init\(\)|\[\s*\]|\[\s*:\s*\])/.test(body.trim())) {
      if (canAdd(match.file, "catch-return-nil-empty")) hints.push({ file: match.file, line: catchLine, pattern: "catch-return-nil-empty", context: body.split("\n")[0], inDiff, flags: {} });
    } else if (/(Logger|os_log|log\.|print\(|debugPrint\()/.test(body) && /return\s+(nil|\[\s*\])/.test(body)) {
      if (canAdd(match.file, "log-then-return-nil")) hints.push({ file: match.file, line: catchLine, pattern: "log-then-return-nil", context: body.split("\n").slice(0, 2).join("; "), inDiff, flags: {} });
    }
  }

  // --- try? analysis ---
  const tryOptionals = await grep("try\\?", repoPath, { glob: "*.swift" });
  for (const match of tryOptionals) {
    const c = match.content;
    if (c.trimStart().startsWith("//")) continue;
    const filePath = `${repoPath}/${match.file}`;
    const lines = await readFileLines(filePath);
    if (isTestFile([...lines.values()].join("\n"))) continue;
    if (/#Preview|PreviewProvider|@Previewable/.test(c)) continue;
    if (/Task\.sleep/.test(c)) continue;
    if (/\?\?/.test(c)) continue;
    const inDiff = isInDiff(diffFiles, match.file, match.line);

    if (/modelContext\.save|context\.save|viewContext\.save|\.save\(\)/.test(c)) {
      if (canAdd(match.file, "try?-save")) hints.push({ file: match.file, line: match.line, pattern: "try?-save", context: c.trim(), inDiff, flags: {} });
    } else if (/try\?\s*await/.test(c) && /URLSession|\.data\(from|\.data\(for|session\.data|fetch|download/.test(c)) {
      if (canAdd(match.file, "try?-network")) hints.push({ file: match.file, line: match.line, pattern: "try?-network", context: c.trim(), inDiff, flags: {} });
    }
  }

  // --- Multi-catch-return-nil functions ---
  for (const filePath of swiftFiles) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    if (isTestFile([...lines.values()].join("\n"))) continue;

    let func: { name: string; start: number; nils: number[]; depth: number; inCatch: boolean; catchDepth: number } | null = null;
    for (const [lineNum, line] of lines) {
      const fm = line.match(/func\s+(\w+)/);
      if (fm && /->/.test(line) && !/\bthrows\b/.test(line)) {
        func = { name: fm[1], start: lineNum, nils: [], depth: 0, inCatch: false, catchDepth: 0 };
      }
      if (!func) continue;
      for (const ch of line) { if (ch === "{") func.depth++; if (ch === "}") { func.depth--; if (func.inCatch && func.depth < func.catchDepth) func.inCatch = false; } }
      if (/}\s*catch|catch\s*\{|catch\s+let/.test(line)) { func.inCatch = true; func.catchDepth = func.depth; }
      if (func.inCatch && /return\s+nil/.test(line)) func.nils.push(lineNum);
      if (func.depth <= 0 && lineNum > func.start) {
        if (func.nils.length >= 2) {
          const inDiff = func.nils.some(l => isInDiff(diffFiles, relPath, l));
          if (canAdd(relPath, "multi-catch-return-nil")) hints.push({ file: relPath, line: func.start, pattern: "multi-catch-return-nil", context: `func ${func.name}() returns nil in ${func.nils.length} catch paths`, inDiff, flags: { funcName: func.name, nilCount: func.nils.length } });
        }
        func = null;
      }
    }
  }

  // --- Empty function stubs ---
  for (const filePath of swiftFiles) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    if (isTestFile([...lines.values()].join("\n"))) continue;

    for (const [lineNum, line] of lines) {
      const fm = line.match(/func\s+(\w+)\s*\(/);
      if (!fm) continue;
      const name = fm[1];
      if (/viewDidLoad|viewWillAppear|viewDidAppear|viewWillDisappear|viewDidDisappear/.test(name)) continue;
      let braceStart = lineNum, found = false;
      for (let i = lineNum; i <= Math.min(lineNum + 3, lines.size); i++) {
        if ((lines.get(i) ?? "").includes("{")) { braceStart = i; found = true; break; }
      }
      if (!found) continue;
      let d = 0, st = false; const bodyLines: string[] = []; let bodyEnd = braceStart;
      for (let i = braceStart; i <= Math.min(braceStart + 15, lines.size); i++) {
        for (const ch of (lines.get(i) ?? "")) { if (ch === "{") { d++; st = true; } if (ch === "}") d--; }
        if (i > braceStart) bodyLines.push((lines.get(i) ?? "").trim());
        if (st && d <= 0) { bodyEnd = i; break; }
      }
      const meaningful = bodyLines.filter(l => l && l !== "}" && !l.startsWith("//"));
      if (meaningful.length === 0 && bodyEnd > braceStart) {
        if (!/save|delete|remove|add|create|update|fetch|load|send|submit|persist|store|insert|edit|modify/i.test(name)) continue;
        if (canAdd(relPath, "empty-function-stub")) hints.push({ file: relPath, line: lineNum, pattern: "empty-function-stub", context: `func ${name}() — empty body`, inDiff: isInDiff(diffFiles, relPath, lineNum), flags: { funcName: name } });
      }
    }
  }

  // --- Metrics & Directions ---
  metrics.totalHints = hints.length;
  metrics.emptyCatch = hints.filter(h => h.pattern === "empty-catch").length;
  metrics.catchOnlyPrint = hints.filter(h => h.pattern === "catch-only-print").length;
  metrics.catchOnlyLog = hints.filter(h => h.pattern === "catch-only-log").length;
  metrics.catchReturnNil = hints.filter(h => h.pattern === "catch-return-nil-empty").length;
  metrics.logThenReturnNil = hints.filter(h => h.pattern === "log-then-return-nil").length;
  metrics.multiCatchReturnNil = hints.filter(h => h.pattern === "multi-catch-return-nil").length;
  metrics.tryOptionalSave = hints.filter(h => h.pattern === "try?-save").length;
  metrics.tryOptionalNetwork = hints.filter(h => h.pattern === "try?-network").length;
  metrics.emptyFunctionStub = hints.filter(h => h.pattern === "empty-function-stub").length;
  metrics.inDiffHints = hints.filter(h => h.inDiff).length;

  const directions: string[] = [];
  const ec = hints.filter(h => h.pattern === "empty-catch" && h.inDiff);
  if (ec.length > 0) directions.push(`${ec.length} empty catch block(s) — errors silently swallowed`);
  const pc = hints.filter(h => h.pattern === "catch-only-print" && h.inDiff);
  if (pc.length > 0) directions.push(`${pc.length} catch block(s) only print() — user sees nothing`);
  const lc = hints.filter(h => h.pattern === "catch-only-log" && h.inDiff);
  if (lc.length > 0) directions.push(`${lc.length} catch block(s) only log — user gets no indication`);
  const sv = hints.filter(h => h.pattern === "try?-save" && h.inDiff);
  if (sv.length > 0) directions.push(`${sv.length} try? on save — persistence failures hidden`);
  const nw = hints.filter(h => h.pattern === "try?-network" && h.inDiff);
  if (nw.length > 0) directions.push(`${nw.length} try? await on network — failure invisible`);
  const rn = hints.filter(h => (h.pattern === "catch-return-nil-empty" || h.pattern === "log-then-return-nil") && h.inDiff);
  if (rn.length > 0) directions.push(`${rn.length} catch returning nil/[] — error info lost`);
  const mn = hints.filter(h => h.pattern === "multi-catch-return-nil" && h.inDiff);
  for (const h of mn) directions.push(`func ${h.flags.funcName}() returns nil in ${h.flags.nilCount} catch paths`);
  const st = hints.filter(h => h.pattern === "empty-function-stub" && h.inDiff);
  if (st.length > 0) directions.push(`${st.length} empty CRUD stub(s) — compile but do nothing`);
  if (directions.length === 0) {
    if (hints.length > 0) directions.push(`${hints.length} silent failure pattern(s) in repo`);
    else directions.push("No silent failure patterns detected");
  }

  return { practice: "silent-failure-patterns", hints, metrics, directions };
}

import type { DiffFile, Hint, PracticeResult, PullRequestMetadata } from "../lib/types";

/** Patterns for completely meaningless commit titles */
const MEANINGLESS_PATTERNS = [
	/^\.+$/, // just dots
	/^-+$/, // just dashes
	/^[a-f0-9]{6,}$/i, // looks like a hash
	/^wip$/i,
	/^asdf/i,
	/^test$/i,
	/^commit$/i,
	/^push$/i,
	/^save$/i,
	/^done$/i,
	/^finished$/i,
	/^final$/i,
	/^temp$/i,
	/^tmp$/i,
	/^xxx$/i,
	/^aaa$/i,
	/^todo$/i,
	/^!!+$/,
	/^\?+$/,
];

/** Single-word commit titles that are too vague (verb without subject) */
const VAGUE_SINGLE_WORD = [
	"fix",
	"fixes",
	"fixed",
	"update",
	"updates",
	"updated",
	"change",
	"changes",
	"changed",
	"stuff",
	"cleanup",
	"refactor",
	"tweaks",
	"tweak",
	"adjust",
	"minor",
	"patch",
	"improve",
	"improvements",
	"edit",
	"edits",
];

/**
 * Check if a title is a "verb + generic object" pattern like "fix stuff", "update code".
 * These lack specificity about WHAT was changed.
 */
const VAGUE_VERB_OBJECT = [
	/^fix\s+(stuff|things|it|this|that|code|bug|bugs|issue|issues|error|errors)$/i,
	/^update\s+(stuff|things|it|this|that|code|file|files)$/i,
	/^change\s+(stuff|things|it|this|that|code)$/i,
	/^small\s+(fix|fixes|changes|update|updates|tweaks?)$/i,
	/^minor\s+(fix|fixes|changes|update|updates|tweaks?)$/i,
	/^some\s+(fix|fixes|changes|update|updates|tweaks?)$/i,
	/^further\s+(fix|fixes|changes|improvements?)$/i,
	/^more\s+(fix|fixes|changes|improvements?)$/i,
	/^apply\s+(feedback|review|suggestions?|changes?)$/i,
	/^address\s+(feedback|review|comments?)$/i,
	/^review\s*(feedback|changes?)?$/i,
	/^ai\s+review$/i,
	/^code\s+cleanup$/i,
	/^code\s+review$/i,
];

/**
 * Classify a single commit title.
 * Returns null if fine, or an object describing the problem.
 */
function classifyCommit(title: string): { category: string; detail: string } | null {
	const trimmed = title.trim();
	const lower = trimmed.toLowerCase();

	// Skip merge commits (auto-generated by Git)
	if (/^Merge\s+(branch|remote|pull|request)/i.test(trimmed)) {
		return null;
	}

	// Extremely short (< 3 chars)
	if (trimmed.length < 3) {
		return {
			category: "meaningless",
			detail: `"${trimmed}" — commit title is too short to be meaningful`,
		};
	}

	// Check meaningless patterns
	for (const pattern of MEANINGLESS_PATTERNS) {
		if (pattern.test(lower)) {
			return { category: "meaningless", detail: `"${trimmed}" — meaningless commit title` };
		}
	}

	// Single-word vague commits
	if (VAGUE_SINGLE_WORD.includes(lower)) {
		return {
			category: "vague-single-word",
			detail: `"${trimmed}" — single verb without describing what was ${lower}ed`,
		};
	}

	// Vague verb+object patterns
	for (const pattern of VAGUE_VERB_OBJECT) {
		if (pattern.test(lower)) {
			return {
				category: "vague-verb-object",
				detail: `"${trimmed}" — generic description, doesn't specify what changed`,
			};
		}
	}

	// "fix + tool name" without context (e.g., "fix swiftlint", "fix pipeline")
	if (/^fix\s+(swiftlint|lint|linting|pipeline|ci|formatting|format)$/i.test(lower)) {
		return {
			category: "tool-fix-only",
			detail: `"${trimmed}" — only names the tool, not what was fixed or why`,
		};
	}

	// Branch-slug-as-title (contains only hyphens separating words, looks like a branch name)
	if (/^\d+[-/]\d+[-/]\d+/.test(trimmed) || /^[a-z]+-[a-z]+-[a-z]+(-[a-z]+)*$/i.test(lower)) {
		return {
			category: "branch-slug-title",
			detail: `"${trimmed}" — looks like a branch name, not a commit message`,
		};
	}

	return null;
}

function extractCommitTitle(commit: { title?: string; message?: string }): string {
	const raw = commit.title?.trim() || commit.message?.trim() || "";
	if (!raw) {
		return "";
	}
	return raw.split("\n", 1)[0].trim();
}

export default async function analyze(
	_repoPath: string,
	diffFiles: Map<string, DiffFile>,
	metadata?: PullRequestMetadata,
): Promise<PracticeResult> {
	const hints: Hint[] = [];
	const title = metadata?.title ?? "";
	const body = metadata?.body ?? "";
	const sourceBranch = metadata?.source_branch ?? "";
	const fileCount = metadata?.changed_files ?? diffFiles.size;
	const commits = metadata?.commits ?? [];

	// ========================
	// PART 1: Analyze MR title
	// ========================
	const titleLower = title.toLowerCase().trim();

	// Meaningless MR title
	const isMeaningless =
		MEANINGLESS_PATTERNS.some((p) => p.test(titleLower)) || title.trim().length < 3;
	if (isMeaningless) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: "meaningless-mr-title",
			context: `MR title: "${title}"`,
			inDiff: true,
			flags: {},
		});
	}

	// Issue-reference-only MR title
	if (/^(resolve|closes?|fix(?:es)?)\s*#\d+$/i.test(titleLower)) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: "issue-ref-only-title",
			context: `MR title "${title}" — issue reference only, no description of what changed`,
			inDiff: true,
			flags: {},
		});
	}

	// Generic-only MR title (verb without subject)
	if (
		(/^(fix|update|change|add|remove|delete|refactor|clean|improve|adjust)\s*$/i.test(titleLower) ||
			VAGUE_VERB_OBJECT.some((pattern) => pattern.test(titleLower))) &&
		!isMeaningless
	) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: "generic-mr-title",
			context: `MR title "${title}" — verb without subject`,
			inDiff: true,
			flags: {},
		});
	}

	// Branch-slug as MR title
	const titleWithoutIssuePrefix = title.replace(/^#?\d+[-/:]\s*/, "").trim();
	const branchNormalized = sourceBranch
		.replace(/-/g, " ")
		.replace(/^(feature|fix|feat|bugfix)\/?/i, "")
		.trim()
		.toLowerCase();
	const titleNormalized = titleWithoutIssuePrefix.replace(/-/g, " ").trim().toLowerCase();
	if (
		branchNormalized.length > 3 &&
		titleNormalized.length > 3 &&
		branchNormalized === titleNormalized
	) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: "branch-slug-mr-title",
			context: `MR title "${title}" appears to be the branch name "${sourceBranch}" reformatted`,
			inDiff: true,
			flags: {},
		});
	}

	// ============================
	// PART 2: Analyze EACH commit
	// ============================
	const nonMergeCommits = commits.filter((commit) => {
		const commitTitle = extractCommitTitle(commit);
		return commitTitle.length > 0 && !/^Merge\s+(branch|remote|pull|request)/i.test(commitTitle);
	});
	const badCommits: Array<{ sha: string; title: string; category: string; detail: string }> = [];

	for (const commit of nonMergeCommits) {
		const commitTitle = extractCommitTitle(commit);
		const classification = classifyCommit(commitTitle);
		if (classification) {
			badCommits.push({
				sha: commit.sha ?? "unknown",
				title: commitTitle,
				...classification,
			});
		}
	}

	// Surface individual bad commits
	for (const bad of badCommits) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: `bad-commit-${bad.category}`,
			context: bad.detail,
			inDiff: true,
			flags: { sha: bad.sha },
		});
	}

	// ============================
	// PART 3: Commit-level patterns
	// ============================

	// Duplicate commit messages (same title used more than once)
	if (nonMergeCommits.length >= 2) {
		const titleCounts = new Map<string, number>();
		for (const c of nonMergeCommits) {
			const t = extractCommitTitle(c).toLowerCase();
			if (t.length > 0) {
				titleCounts.set(t, (titleCounts.get(t) ?? 0) + 1);
			}
		}
		const duplicates = [...titleCounts.entries()].filter(([, count]) => count > 1);
		for (const [dupTitle, count] of duplicates) {
			hints.push({
				file: "_MR_",
				line: 0,
				pattern: "duplicate-commit-messages",
				context: `Commit message "${dupTitle}" appears ${count} times — suggests work was not properly organized into atomic commits`,
				inDiff: true,
				flags: { count },
			});
		}
	}

	// Ratio of bad commits to total
	const badRatio = nonMergeCommits.length > 0 ? badCommits.length / nonMergeCommits.length : 0;

	// Kitchen-sink MR (20+ files, 4+ directories)
	if (fileCount >= 20) {
		const dirs = new Set<string>();
		for (const path of diffFiles.keys()) {
			const parts = path.split("/");
			if (parts.length >= 2) dirs.add(parts.slice(0, -1).join("/"));
		}
		if (dirs.size >= 4) {
			hints.push({
				file: "_MR_",
				line: 0,
				pattern: "kitchen-sink",
				context: `${fileCount} files across ${dirs.size} directories — very large changeset`,
				inDiff: true,
				flags: { fileCount, dirCount: dirs.size },
			});
		}
	}

	// ========================
	// METRICS
	// ========================
	const metrics = {
		totalHints: hints.length,
		titleLength: title.length,
		fileCount,
		hasBody: body.length > 0 ? 1 : 0,
		totalCommits: commits.length,
		nonMergeCommits: nonMergeCommits.length,
		badCommitCount: badCommits.length,
		badCommitRatio: Math.round(badRatio * 100),
		duplicateCommitGroups: hints.filter((h) => h.pattern === "duplicate-commit-messages").length,
	};

	// ========================
	// DIRECTIONS
	// ========================
	const directions: string[] = [];

	if (isMeaningless) {
		directions.push(`SIGNAL: MR title "${title}" communicates nothing about the change`);
	}
	if (hints.some((h) => h.pattern === "issue-ref-only-title")) {
		directions.push(`SIGNAL: MR title is only an issue reference — no description of what changed`);
	}
	if (hints.some((h) => h.pattern === "branch-slug-mr-title")) {
		directions.push(`SIGNAL: MR title appears to be the branch name, not a meaningful description`);
	}

	if (badCommits.length > 0) {
		const categories = [...new Set(badCommits.map((b) => b.category))];
		const examples = badCommits
			.slice(0, 3)
			.map((b) => `"${b.title}"`)
			.join(", ");
		directions.push(
			`SIGNAL: ${badCommits.length}/${nonMergeCommits.length} non-merge commits have poor messages (${categories.join(", ")}). Examples: ${examples}`,
		);
	}

	if (hints.some((h) => h.pattern === "duplicate-commit-messages")) {
		const dupHints = hints.filter((h) => h.pattern === "duplicate-commit-messages");
		const dupExamples = dupHints.map((h) => h.context.split('"')[1]).join(", ");
		directions.push(
			`SIGNAL: Duplicate commit messages found: "${dupExamples}" — commits are not atomic`,
		);
	}

	if (badRatio >= 0.5 && nonMergeCommits.length >= 3) {
		directions.push(
			`SIGNAL: ${Math.round(badRatio * 100)}% of commits have poor messages — overall commit discipline is weak`,
		);
	}

	if (hints.some((h) => h.pattern === "kitchen-sink")) {
		directions.push(`SIGNAL: Large MR (${fileCount} files) — investigate if scope is justified`);
	}

	if (directions.length === 0) {
		if (nonMergeCommits.length === 0 && commits.length > 0) {
			directions.push("All commits are merge commits — no commit messages to evaluate");
		} else if (nonMergeCommits.length === 0) {
			directions.push("No commits found in metadata — cannot evaluate commit discipline");
		} else {
			directions.push("Commit messages and MR title look reasonable");
		}
	}

	return { practice: "commit-discipline", hints, metrics, directions };
}

import type { DiffFile, Hint, PracticeResult, PullRequestMetadata } from "../lib/types";

/** Known MR template placeholder strings */
const TEMPLATE_PLACEHOLDERS = [
	"Briefly describe what was implemented",
	"Link the related issue",
	"List steps to verify the changes",
	"State which acceptance criteria are fulfilled",
	"## Changes",
	"## Testing",
	"Add screenshots if",
	"Screenshots attached",
];

/** Lines that are part of template checklists, not real description content */
const CHECKLIST_PATTERNS = [
	/^-\s*\[[ x]\]\s/i, // - [ ] or - [x] checkbox
	/^##\s*(Definition of Done|Screenshots|DoD)/i, // DoD section headers
	/^##\s*📌|^##\s*Title/i, // decorated section headers
	/^\*\*Example:?\*\*/i, // template example text
	/^Closes?\s*#\d+/i, // "Closes #N"
	/^Resolves?\s*#\d+/i, // "Resolves #N"
	/^Fix(?:es)?\s*#\d+/i, // "Fixes #N"
	/^origin\//, // branch reference pasted as screenshot
	/^\s*$/, // blank lines
];

/**
 * Extract "real" description content from the MR body:
 * strips template sections, checklists, issue refs, and headers.
 */
function extractRealContent(body: string): string {
	const lines = body.split("\n");
	const contentLines: string[] = [];

	let inChecklistSection = false;

	for (const line of lines) {
		const trimmed = line.trim();

		// Entering a "Definition of Done" or similar checklist section
		if (/^##\s*(Definition of Done|DoD|Checklist)/i.test(trimmed)) {
			inChecklistSection = true;
			continue;
		}
		// New ## section exits checklist mode
		if (/^##\s/.test(trimmed) && inChecklistSection) {
			inChecklistSection = false;
		}
		if (inChecklistSection) continue;

		// Skip lines matching checklist/template patterns
		if (CHECKLIST_PATTERNS.some((p) => p.test(trimmed))) continue;

		// Skip template placeholders
		if (TEMPLATE_PLACEHOLDERS.some((p) => trimmed.includes(p))) continue;

		// Skip markdown headers that are just section labels with no content
		if (/^#{1,3}\s*$/.test(trimmed)) continue;

		// Skip ## Description header itself (we want the content below it)
		if (/^##\s*(Description|Summary|Overview)\s*$/i.test(trimmed)) continue;

		// Skip lines that are just markdown formatting (---, ***, etc.)
		if (/^[-*_]{3,}\s*$/.test(trimmed)) continue;

		contentLines.push(trimmed);
	}

	return contentLines.join(" ").replace(/\s+/g, " ").trim();
}

/**
 * Normalize a string for comparison: lowercase, remove issue refs, punctuation, extra spaces.
 */
function normalize(s: string): string {
	return s
		.toLowerCase()
		.replace(/#\d+[:\s]*/g, "") // strip issue refs like "#41:"
		.replace(/[^a-z0-9\s]/g, " ") // strip punctuation
		.replace(/\s+/g, " ")
		.trim();
}

/**
 * Check if body text is essentially a copy of commit messages.
 */
function isCommitMessagePaste(
	realContent: string,
	commits: Array<{ title?: string; message?: string }>,
): { isMatch: boolean; detail: string } {
	if (!commits || commits.length === 0) return { isMatch: false, detail: "" };

	const normalizedContent = normalize(realContent);
	if (normalizedContent.length < 5) return { isMatch: false, detail: "" };

	// Check if body is just commit titles concatenated
	const commitTitles = commits
		.map((commit) => normalize(commit.title?.trim() || commit.message?.trim() || ""))
		.filter(Boolean);
	const commitConcat = commitTitles.join(" ");

	// Jaccard-like overlap: how many words in the content also appear in commits
	const contentWords = new Set(normalizedContent.split(/\s+/).filter((w) => w.length > 2));
	const commitWords = new Set(commitConcat.split(/\s+/).filter((w) => w.length > 2));

	if (contentWords.size === 0) return { isMatch: false, detail: "" };

	let overlapCount = 0;
	for (const w of contentWords) {
		if (commitWords.has(w)) overlapCount++;
	}
	const overlapRatio = overlapCount / contentWords.size;

	if (overlapRatio >= 0.8) {
		return {
			isMatch: true,
			detail: `${Math.round(overlapRatio * 100)}% of description words also appear in commit titles`,
		};
	}

	return { isMatch: false, detail: "" };
}

export default async function analyze(
	_repoPath: string,
	diffFiles: Map<string, DiffFile>,
	metadata?: PullRequestMetadata,
): Promise<PracticeResult> {
	const hints: Hint[] = [];
	const title = metadata?.title ?? "";
	const body = metadata?.body ?? "";
	const fileCount = metadata?.changed_files ?? diffFiles.size;
	const commits = metadata?.commits ?? [];

	// Extract actual descriptive content (strip template/checklist/issue-refs)
	const realContent = extractRealContent(body);
	const realContentWords = realContent.split(/\s+/).filter(Boolean);
	const realWordCount = realContentWords.length;

	// Full body metrics
	const bodyTrimmed = body.replace(/\s+/g, " ").trim();
	const isEmpty = !bodyTrimmed;

	// --- CHECK 1: Completely empty body ---
	if (isEmpty) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: "empty-body",
			context: `${fileCount} file(s) changed with completely empty MR description`,
			inDiff: true,
			flags: { fileCount, bodyLength: 0 },
		});
	}

	// --- CHECK 2: Body just repeats the title ---
	if (!isEmpty) {
		const normalizedTitle = normalize(title);
		const normalizedContent = normalize(realContent);
		if (normalizedTitle.length > 3 && normalizedContent.length > 0) {
			const titleWords = normalizedTitle.split(/\s+/).filter((w) => w.length > 2);
			const contentWords = normalizedContent.split(/\s+/).filter((w) => w.length > 2);

			// Exact or near-exact match: content is essentially the same as the title
			const isExactRepeat = normalizedContent === normalizedTitle;

			// Content is a subset of the title (title contains all content)
			const isSubset =
				titleWords.length > 0 &&
				contentWords.length > 0 &&
				contentWords.every((w) => titleWords.includes(w));

			// Content is the title with no meaningful additions:
			// count how many content words are NOT in the title
			const extraWords = contentWords.filter((w) => !titleWords.includes(w));
			const extraRatio = contentWords.length > 0 ? extraWords.length / contentWords.length : 0;
			// If less than 20% of content words are new compared to the title, it's a repeat
			const isNearRepeat =
				contentWords.length > 0 &&
				contentWords.length <= titleWords.length * 1.5 &&
				extraRatio < 0.2;

			if (isExactRepeat || isSubset || isNearRepeat) {
				hints.push({
					file: "_MR_",
					line: 0,
					pattern: "body-repeats-title",
					context: `Description "${realContent.slice(0, 80)}" just repeats the MR title — adds no new information`,
					inDiff: true,
					flags: {},
				});
			}
		}
	}

	// --- CHECK 3: Body is only a checklist/template with no real content ---
	if (!isEmpty && realWordCount <= 3 && body.length > 30) {
		// Body has substantial text but it's all template/checklist
		const checkboxCount = (body.match(/-\s*\[[ x]\]/gi) ?? []).length;
		if (checkboxCount >= 2) {
			hints.push({
				file: "_MR_",
				line: 0,
				pattern: "checklist-only-body",
				context: `Body has ${checkboxCount} checkboxes but no actual description of what changed (${realWordCount} words of real content)`,
				inDiff: true,
				flags: { checkboxCount, realWordCount },
			});
		}
	}

	// --- CHECK 4: Unmodified template placeholders ---
	let templatePlaceholdersFound = 0;
	for (const placeholder of TEMPLATE_PLACEHOLDERS) {
		if (body.includes(placeholder)) templatePlaceholdersFound++;
	}
	if (templatePlaceholdersFound >= 2 && realWordCount <= 5) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: "unmodified-template",
			context: `${templatePlaceholdersFound} template placeholder(s) found with no meaningful custom content`,
			inDiff: true,
			flags: {},
		});
	}

	// --- CHECK 5: Issue-reference-only body ---
	// More flexible: body might have template but the only "real" content is "Closes #N"
	const issueRefOnlyContent = bodyTrimmed
		.replace(/-\s*\[[ x]\][^\n]*/gi, "")
		.replace(/##[^\n]*/g, "")
		.replace(/\*\*[^\n]*\*\*/g, "")
		.replace(/[#\-*>\s]/g, "")
		.trim();
	if (!isEmpty && /^(closes?|fix(?:es)?|resolve[sd]?)\s*#?\d+$/i.test(issueRefOnlyContent)) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: "issue-ref-only-body",
			context: `Body is only "${issueRefOnlyContent}" with template/formatting — no explanation of what changed`,
			inDiff: true,
			flags: {},
		});
	}

	// --- CHECK 6: Body is just commit messages pasted ---
	if (!isEmpty && realWordCount > 3 && commits.length > 0) {
		const { isMatch, detail } = isCommitMessagePaste(realContent, commits);
		if (isMatch) {
			hints.push({
				file: "_MR_",
				line: 0,
				pattern: "commit-paste-body",
				context: `Description appears to be pasted commit messages (${detail})`,
				inDiff: true,
				flags: {},
			});
		}
	}

	// --- CHECK 7: Generic title ---
	const normalizedTitle = title.toLowerCase().trim();
	const genericTitles = [
		"update",
		"fix",
		"changes",
		"small fixes",
		"further improvements",
		"improvements",
		"wip",
		"done",
	];
	const vagueTitlePatterns = [
		/^update\s+(stuff|things|code|files?)$/i,
		/^fix\s+(stuff|things|code|issues?|bugs?)$/i,
		/^change\s+(stuff|things|code)$/i,
	];
	if (
		genericTitles.includes(normalizedTitle) ||
		vagueTitlePatterns.some((pattern) => pattern.test(normalizedTitle))
	) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: "generic-title",
			context: `Title "${title}" is too generic — doesn't describe WHAT changed`,
			inDiff: true,
			flags: {},
		});
	}

	// --- CHECK 8: Brief description for large MR ---
	if (
		!isEmpty &&
		realWordCount > 0 &&
		realWordCount < 10 &&
		fileCount > 5 &&
		!hints.some((h) => h.pattern === "body-repeats-title" || h.pattern === "checklist-only-body")
	) {
		hints.push({
			file: "_MR_",
			line: 0,
			pattern: "brief-description-large-mr",
			context: `Only ${realWordCount} words of description for ${fileCount} files changed — insufficient context for reviewers`,
			inDiff: true,
			flags: { realWordCount, fileCount },
		});
	}

	// Body quality metrics
	const hasScreenshots = /!\[.*\]\(.*\)|screenshot|\.png|\.jpg|\.jpeg|\.gif/i.test(body);
	const checkboxCount = (body.match(/-\s*\[[ x]\]/gi) ?? []).length;

	const metrics = {
		totalHints: hints.length,
		bodyLength: body.length,
		bodyWordCount: bodyTrimmed.split(/\s+/).filter(Boolean).length,
		realContentWordCount: realWordCount,
		templatePlaceholders: templatePlaceholdersFound,
		checkboxCount,
		hasScreenshots: hasScreenshots ? 1 : 0,
		fileCount,
		commitCount: commits.length,
	};

	// --- DIRECTIONS ---
	const directions: string[] = [];
	if (hints.some((h) => h.pattern === "empty-body")) {
		directions.push(`SIGNAL: MR has ${fileCount} files changed but completely empty description`);
	}
	if (hints.some((h) => h.pattern === "body-repeats-title")) {
		directions.push(
			"SIGNAL: MR description just repeats the title — provides no additional context for reviewers",
		);
	}
	if (hints.some((h) => h.pattern === "checklist-only-body")) {
		directions.push(
			"SIGNAL: MR body contains only a template checklist (Definition of Done checkboxes) with no actual description of what was implemented or why",
		);
	}
	if (hints.some((h) => h.pattern === "unmodified-template")) {
		directions.push("SIGNAL: MR template was not filled in — still contains placeholder text");
	}
	if (hints.some((h) => h.pattern === "issue-ref-only-body")) {
		directions.push("SIGNAL: MR body only has an issue reference with no description of changes");
	}
	if (hints.some((h) => h.pattern === "commit-paste-body")) {
		directions.push(
			"SIGNAL: MR description appears to be pasted commit messages rather than a meaningful summary",
		);
	}
	if (hints.some((h) => h.pattern === "brief-description-large-mr")) {
		directions.push(
			`SIGNAL: Very brief description (${realWordCount} words) for a large MR (${fileCount} files) — reviewer cannot understand scope without reading all the code`,
		);
	}
	if (hints.some((h) => h.pattern === "generic-title")) {
		directions.push(`SIGNAL: MR title "${title}" is too generic`);
	}
	if (hints.length === 0) {
		if (realWordCount > 10) {
			directions.push("MR description has substantive content");
		} else if (fileCount <= 3 && realWordCount > 0) {
			directions.push("Small MR with minimal description — may be acceptable for this scope");
		} else {
			directions.push("MR description is brief — verify if sufficient for the scope of changes");
		}
	}

	return { practice: "mr-description-quality", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { grep, matchesToHints } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

/** Shannon entropy of a string */
function entropy(s: string): number {
  const freq = new Map<string, number>();
  for (const c of s) freq.set(c, (freq.get(c) ?? 0) + 1);
  let e = 0;
  for (const count of freq.values()) {
    const p = count / s.length;
    e -= p * Math.log2(p);
  }
  return e;
}

/** Known API key prefixes */
const KEY_PREFIXES = [
  { prefix: "sk-", name: "OpenAI/OpenWebUI" },
  { prefix: "ghp_", name: "GitHub PAT" },
  { prefix: "gho_", name: "GitHub OAuth" },
  { prefix: "AKIA", name: "AWS Access Key" },
  { prefix: "xoxb-", name: "Slack Bot" },
  { prefix: "xoxp-", name: "Slack User" },
  { prefix: "AIza", name: "Google API" },
  { prefix: "pk_live_", name: "Stripe Public" },
  { prefix: "sk_live_", name: "Stripe Secret" },
  { prefix: "pk_test_", name: "Stripe Test" },
  { prefix: "sk_test_", name: "Stripe Test" },
];

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints = [];

  // Pattern 1: Known key prefixes
  for (const { prefix, name } of KEY_PREFIXES) {
    const matches = await grep(`"${prefix}`, repoPath, { fixedString: true });
    for (const m of matches) {
      if (m.content.trimStart().startsWith("//")) continue;
      const inDiff = isInDiff(diffFiles, m.file, m.line);
      hints.push({
        file: m.file, line: m.line, pattern: `known-prefix:${prefix}`,
        context: m.content,
        inDiff,
        flags: { keyType: name, prefix },
      });
    }
  }

  // Pattern 2: Private keys
  const privateKeys = await grep("BEGIN.*PRIVATE KEY", repoPath, { glob: "*" });
  for (const m of privateKeys) {
    hints.push({
      file: m.file, line: m.line, pattern: "private-key",
      context: m.content,
      inDiff: isInDiff(diffFiles, m.file, m.line),
      flags: {},
    });
  }

  // Pattern 3: High-entropy strings assigned to suspicious variable names
  const suspiciousVars = await grep('(apiKey|api_key|token|secret|password|pwd|auth|credential|API_KEY)\\s*=\\s*"', repoPath);
  // Deduplicate by file:line
  const seen = new Set(suspiciousVars.map(m => `${m.file}:${m.line}`));
  for (const m of suspiciousVars) {
    if (m.content.trimStart().startsWith("//")) continue;
    // Skip Logger subsystem identifiers (not secrets)
    if (/Logger\s*\(/.test(m.content) || /Logger\(subsystem:/.test(m.content)) continue;
    if (/Bundle\.main\.bundleIdentifier|\.bundleIdentifier/.test(m.content)) continue;
    // Extract the string value
    const strMatch = m.content.match(/"([^"]{8,})"/);
    if (!strMatch) continue;
    const value = strMatch[1];
    // Skip placeholders
    if (/YOUR_|REPLACE|changeme|xxx|placeholder|example|TODO/i.test(value)) continue;
    // Skip empty or very short
    if (value.length < 10) continue;
    // Check entropy
    const e = entropy(value);
    if (e < 3.0) continue; // low entropy = not a secret

    const inDiff = isInDiff(diffFiles, m.file, m.line);
    hints.push({
      file: m.file, line: m.line, pattern: "high-entropy-secret",
      context: m.content,
      inDiff,
      flags: { entropy: parseFloat(e.toFixed(2)), valueLength: value.length },
    });
  }

  // Pattern 4: Hardcoded URL with credentials (postgres://, mysql://, mongodb://)
  const connStrings = await grep('(postgres|mysql|mongodb|redis)://[^"]*:[^"]*@', repoPath, { glob: "*" });
  for (const m of connStrings) {
    if (m.content.trimStart().startsWith("//") && !m.content.includes("://")) continue;
    hints.push({
      file: m.file, line: m.line, pattern: "connection-string-with-credentials",
      context: m.content,
      inDiff: isInDiff(diffFiles, m.file, m.line),
      flags: {},
    });
  }

  // Pattern 5: Hardcoded long alphanumeric strings (API keys without variable name hints)
  const longStrings = await grep('"[a-zA-Z0-9+/]{20,}"', repoPath);
  for (const m of longStrings) {
    if (m.content.trimStart().startsWith("//")) continue;
    // Skip Logger configuration lines (subsystem/category identifiers, not secrets)
    if (/subsystem:|category:/.test(m.content)) continue;
    if (/\.bundleIdentifier/.test(m.content)) continue;
    const strMatch = m.content.match(/"([a-zA-Z0-9+/]{20,})"/);
    if (!strMatch) continue;
    const value = strMatch[1];
    // Skip already-caught patterns
    if (hints.some(h => h.file === m.file && h.line === m.line)) continue;
    // Must have high entropy
    if (entropy(value) < 3.5) continue;
    // Skip UUIDs
    if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(value)) continue;
    // Skip URL paths and common non-secret strings
    if (value.includes("/") || value.includes("http") || value.includes("www")) continue;
    // Skip bundle identifiers and reverse DNS
    if (/^[a-z]+\.[a-z]+\./i.test(value)) continue;

    hints.push({
      file: m.file, line: m.line, pattern: "suspicious-long-string",
      context: m.content,
      inDiff: isInDiff(diffFiles, m.file, m.line),
      flags: { entropy: parseFloat(entropy(value).toFixed(2)), length: value.length },
    });
  }

  const metrics = {
    totalMatches: hints.length,
    knownPrefixes: hints.filter(h => h.pattern.startsWith("known-prefix")).length,
    highEntropy: hints.filter(h => h.pattern === "high-entropy-secret" || h.pattern === "suspicious-long-string").length,
    inDiffMatches: hints.filter(h => h.inDiff).length,
  };

  const directions: string[] = [];
  const knownKeys = hints.filter(h => h.pattern.startsWith("known-prefix"));
  if (knownKeys.length > 0) {
    const types = [...new Set(knownKeys.map(h => h.flags.keyType))].join(", ");
    directions.push(`${knownKeys.length} known API key pattern(s) found: ${types} — verify if real and require immediate rotation`);
  }
  const highEntropy = hints.filter(h => h.pattern === "high-entropy-secret");
  if (highEntropy.length > 0) {
    directions.push(`${highEntropy.length} high-entropy string(s) in secret-named variables — investigate if these are real credentials`);
  }
  const longStringsInDiff = hints.filter(h => h.pattern === "suspicious-long-string" && h.inDiff);
  if (longStringsInDiff.length > 0) {
    directions.push(`${longStringsInDiff.length} suspicious long string(s) on changed lines — check if these are API keys or tokens`);
  }
  if (hints.length === 0) {
    directions.push("No hardcoded secrets detected — repo looks clean");
  }

  return { practice: "hardcoded-secrets", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { findFiles, readFileLines } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints = [];
  const swiftFiles = await findFiles(repoPath, "swift");

  for (const filePath of swiftFiles) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    const allText = [...lines.values()].join("\n");

    if (!/:\s*View\s*\{/.test(allText)) continue;

    for (const [lineNum, line] of lines) {
      // Image(systemName:) without accessibility label
      if (/Image\(systemName:/.test(line)) {
        // Check surrounding lines for .accessibilityLabel or being inside Button/Label
        let hasLabel = false;
        let insideLabeledContainer = false;
        for (let i = Math.max(1, lineNum - 3); i <= Math.min(lines.size, lineNum + 5); i++) {
          const l = lines.get(i) ?? "";
          if (/\.accessibilityLabel|\.accessibilityHidden/.test(l)) hasLabel = true;
          if (/Button\(.*,\s*systemImage:|Label\(.*,\s*systemImage:/.test(l)) insideLabeledContainer = true;
          if (/Button.*\{/.test(l) && i < lineNum) {
            // Check if button has Text sibling
            for (let j = i; j <= Math.min(lines.size, lineNum + 3); j++) {
              if (/Text\(/.test(lines.get(j) ?? "")) insideLabeledContainer = true;
            }
          }
        }
        if (!hasLabel && !insideLabeledContainer) {
          hints.push({
            file: relPath, line: lineNum, pattern: "unlabeled-image",
            context: line.trim(),
            inDiff: isInDiff(diffFiles, relPath, lineNum),
            flags: {},
          });
        }
      }

      // Hardcoded font sizes
      if (/\.font\(\.system\(size:\s*\d+/.test(line)) {
        hints.push({
          file: relPath, line: lineNum, pattern: "hardcoded-font-size",
          context: line.trim(),
          inDiff: isInDiff(diffFiles, relPath, lineNum),
          flags: {},
        });
      }

      // onTapGesture without accessibility traits
      if (/\.onTapGesture/.test(line)) {
        let hasTraits = false;
        for (let i = Math.max(1, lineNum - 2); i <= Math.min(lines.size, lineNum + 5); i++) {
          if (/\.accessibilityAddTraits|\.accessibilityLabel/.test(lines.get(i) ?? "")) hasTraits = true;
        }
        if (!hasTraits) {
          hints.push({
            file: relPath, line: lineNum, pattern: "tap-without-traits",
            context: line.trim(),
            inDiff: isInDiff(diffFiles, relPath, lineNum),
            flags: {},
          });
        }
      }
    }
  }

  const metrics = {
    totalHints: hints.length,
    unlabeledImages: hints.filter(h => h.pattern === "unlabeled-image").length,
    hardcodedFonts: hints.filter(h => h.pattern === "hardcoded-font-size").length,
    tapWithoutTraits: hints.filter(h => h.pattern === "tap-without-traits").length,
    inDiffHints: hints.filter(h => h.inDiff).length,
  };

  const directions: string[] = [];
  const inDiffHints = hints.filter(h => h.inDiff);
  if (inDiffHints.length > 0) {
    const byPattern = new Map<string, number>();
    for (const h of inDiffHints) byPattern.set(h.pattern, (byPattern.get(h.pattern) ?? 0) + 1);
    for (const [p, c] of byPattern) {
      directions.push(`${c} ${p.replace(/-/g, " ")} issue(s) on changed lines`);
    }
  }
  if (directions.length === 0 && hints.length > 0) {
    directions.push(`${hints.length} accessibility issue(s) in repo — check if any on changed lines`);
  }
  if (hints.length === 0) {
    directions.push("No obvious accessibility issues found");
  }

  return { practice: "accessibility-support", hints, metrics, directions };
}

import type { PracticeResult, DiffFile } from "../lib/types";
import { grep, findFiles, readFileLines } from "../lib/grep";
import { isInDiff } from "../lib/diff-parser";

const NETWORKING_RE = /URLSession|\.data\(from|\.dataTask|\.request\(|Alamofire|AF\.|Data\(\s*contentsOf\s*:/;
const ASYNC_BLOCK_RE = /\.(task|onAppear)\s*\{/;
const LOADING_RE = /ProgressView|\.redacted\(|shimmer|skeleton|isLoading|showLoading|LoadingState\.loading|\.loading\b/;
const ERROR_RE = /errorMessage|errorText|showError|isError|hasError|\.alert\s*\(.*(?:error|Error|fail)|ContentUnavailableView|LoadingState\.failed|\.failed\b|alertError|displayError/;
const BUNDLE_DATA_RE = /Data\(\s*contentsOf\s*:\s*Bundle\.main/;
const MEANINGFUL_AWAIT_RE = /await\s+(?!Task\.sleep)(?!withAnimation)\w/;
const FETCH_METHOD_RE = /await\s+(?:\w+\.)*(?:fetch|load|get|retrieve|request|download|search|query|refresh|sync|update|pull)\w*\s*\(/i;
const AWAIT_VM_RE = /await\s+(?:viewModel|vm|model|manager|service|store|repository|api|client|provider)\.\w+/i;

function findLine(lines: Map<number, string>, re: RegExp): number | null {
  for (const [n, t] of lines) if (re.test(t)) return n;
  return null;
}

export default async function analyze(repoPath: string, diffFiles: Map<string, DiffFile>): Promise<PracticeResult> {
  const hints: Array<{ file: string; line: number; pattern: string; context: string; inDiff: boolean; flags: Record<string, any> }> = [];
  const swiftFiles = await findFiles(repoPath, "swift");

  for (const filePath of swiftFiles) {
    const lines = await readFileLines(filePath);
    const relPath = filePath.replace(repoPath + "/", "");
    const allText = [...lines.values()].join("\n");

    if (!/:\s*View\s*\{/.test(allText)) continue;
    if (/import\s+XCTest|import\s+Testing/.test(allText)) continue;
    if (/@Query|@AppStorage/.test(allText) && !NETWORKING_RE.test(allText) && !MEANINGFUL_AWAIT_RE.test(allText)) continue;

    // Detect networking
    let reason = "";
    let netLine = 1;
    const hasRemoteData = /Data\(\s*contentsOf\s*:/.test(allText) && !BUNDLE_DATA_RE.test(allText);

    if (/URLSession|\.data\(from|\.dataTask/.test(allText)) { reason = "URLSession"; netLine = findLine(lines, /URLSession|\.data\(from/) ?? 1; }
    else if (/Alamofire|AF\./.test(allText)) { reason = "Alamofire"; netLine = findLine(lines, /Alamofire|AF\./) ?? 1; }
    else if (hasRemoteData) { reason = "Data(contentsOf:)"; netLine = findLine(lines, /Data\(\s*contentsOf/) ?? 1; }
    else if (ASYNC_BLOCK_RE.test(allText) && MEANINGFUL_AWAIT_RE.test(allText)) {
      if (FETCH_METHOD_RE.test(allText)) { reason = "async fetch in .task"; netLine = findLine(lines, ASYNC_BLOCK_RE) ?? 1; }
      else if (AWAIT_VM_RE.test(allText)) { reason = "async viewModel call"; netLine = findLine(lines, AWAIT_VM_RE) ?? 1; }
    }

    if (!reason) continue;

    const hasLoading = LOADING_RE.test(allText);
    const hasError = ERROR_RE.test(allText);
    const inDiff = [...diffFiles.keys()].some(k => relPath.endsWith(k) || k.endsWith(relPath));

    if (!hasLoading && !hasError) {
      hints.push({ file: relPath, line: netLine, pattern: "missing-both-states", context: `View (${reason}) with neither loading nor error state`, inDiff, flags: { reason, syncNetworking: hasRemoteData } });
    } else if (!hasLoading) {
      hints.push({ file: relPath, line: netLine, pattern: "missing-loading-state", context: `View (${reason}) without loading indicator`, inDiff, flags: { reason } });
    } else if (!hasError) {
      const ctx = `View (${reason}) without error state` + (/ProgressView/.test(allText) ? " — infinite spinner risk" : "");
      hints.push({ file: relPath, line: netLine, pattern: "missing-error-state", context: ctx, inDiff, flags: { reason, infiniteSpinnerRisk: /ProgressView/.test(allText) && !hasError } });
    }

    if (/Text\(.*\.localizedDescription/.test(allText) && !/\/\/.*localizedDescription/.test(allText)) {
      hints.push({ file: relPath, line: findLine(lines, /\.localizedDescription/) ?? netLine, pattern: "raw-error-string", context: "Shows error.localizedDescription to user", inDiff, flags: {} });
    }
  }

  const metrics: Record<string, number> = {
    totalHints: hints.length,
    missingBoth: hints.filter(h => h.pattern === "missing-both-states").length,
    missingLoading: hints.filter(h => h.pattern === "missing-loading-state").length,
    missingError: hints.filter(h => h.pattern === "missing-error-state").length,
    rawErrorStrings: hints.filter(h => h.pattern === "raw-error-string").length,
    inDiffHints: hints.filter(h => h.inDiff).length,
  };

  const directions: string[] = [];
  const mb = hints.filter(h => h.pattern === "missing-both-states" && h.inDiff);
  if (mb.length > 0) directions.push(`${mb.length} view(s) fetch data with NEITHER loading nor error states — MAJOR`);
  const me = hints.filter(h => h.pattern === "missing-error-state" && h.inDiff);
  if (me.length > 0) {
    const spin = me.filter(h => h.flags.infiniteSpinnerRisk);
    let msg = `${me.length} view(s) missing error state`;
    if (spin.length > 0) msg += ` (${spin.length} with infinite-spinner risk)`;
    directions.push(msg);
  }
  const ml = hints.filter(h => h.pattern === "missing-loading-state" && h.inDiff);
  if (ml.length > 0) directions.push(`${ml.length} view(s) missing loading indicator`);
  const re = hints.filter(h => h.pattern === "raw-error-string" && h.inDiff);
  if (re.length > 0) directions.push(`${re.length} view(s) show raw .localizedDescription`);
  if (directions.length === 0) directions.push("No error/loading state issues on changed views");

  return { practice: "error-state-handling", hints, metrics, directions };
}
